/*
 * (#1) Actual Updates: Extracted withTimeout utility to utils.js.
 * (#2) Next Steps: Continue monitoring class size.
 * (#3) Found Errors + Solutions: None.
 */
import { ToxicFilterManager } from './stage/ToxicFilterManager'
import { BaseStageController } from './stage/BaseStageController'
import { CrowdManager } from './stage/CrowdManager'
import { LaneManager } from './stage/LaneManager'
import { EffectManager } from './stage/EffectManager'
import { NoteManager } from './stage/NoteManager'
import { getGigTimeMs } from '../utils/audioEngine'
import { withTimeout } from './stage/utils'
import type { StageControllerOptions } from '../types/components'
import type { RhythmGameRefState } from '../types/rhythmGame'

/**
 * Manages Pixi.js stage lifecycle and rendering updates.
 */
class PixiStageController extends BaseStageController<RhythmGameRefState> {
  // Getters and Setters for backward compatibility with existing tests
  get colorMatrix() {
    return this.toxicFilterManager?.colorMatrix ?? null
  }

  set colorMatrix(value) {
    if (this.toxicFilterManager) {
      this.toxicFilterManager.colorMatrix = value
    }
  }

  get toxicFilters() {
    return this.toxicFilterManager?.toxicFilters ?? null
  }

  set toxicFilters(value) {
    if (this.toxicFilterManager) {
      this.toxicFilterManager.toxicFilters = value
    }
  }

  get isToxicActive() {
    return this.toxicFilterManager?.isToxicActive ?? false
  }

  set isToxicActive(value) {
    if (this.toxicFilterManager) {
      this.toxicFilterManager.isToxicActive = value
    }
  }
  stageContainer: any
  crowdManager: any
  laneManager: any
  effectManager: any
  noteManager: any
  toxicFilterManager: ToxicFilterManager | null

  /**
   * @param {object} params - Controller dependencies.
   */
  constructor(params: any) {
    super(params)
    this.stageContainer = null

    // Managers
    this.crowdManager = null
    this.laneManager = null
    this.effectManager = null
    this.noteManager = null
    this.toxicFilterManager = null
  }

  /**
   * Initializes the Pixi application and stage objects.
   * Called by BaseStageController.init().
   */
  async setup() {
    this._initFilters()
    const loadPromises = this._initManagersAndStartLoading()
    await Promise.all(loadPromises)
    this._finalizeInit()
  }

  /**
   * Initializes stage container and toxic filters.
   * @private
   */
  _initFilters() {
    this.stageContainer = this.container
    this.toxicFilterManager = new ToxicFilterManager()
  }

  /**
   * Initializes managers and starts asset loading.
   * @returns {Promise[]} Array of asset loading promises.
   * @private
   */
  _initManagersAndStartLoading() {
    // Initialize Managers and start loading assets in parallel
    this.crowdManager = new CrowdManager(this.app!, this.stageContainer)
    const crowdLoad = withTimeout(
      this.crowdManager.loadAssets(),
      'Crowd Assets'
    )

    this.laneManager = new LaneManager(
      this.app!,
      this.stageContainer,
      this.gameStateRef
    )
    this.laneManager.init()

    // Rhythm container is needed for effects and notes.
    // LaneManager owns the rhythm container.
    const rhythmContainer = this.laneManager.container

    this.effectManager = new EffectManager(this.app!, rhythmContainer)
    const effectLoad = withTimeout(
      this.effectManager.loadAssets(),
      'Effect Assets'
    )

    this.noteManager = new NoteManager(
      this.app!,
      rhythmContainer,
      this.gameStateRef,
      (x: any, y: any, color: any) =>
        this.effectManager.spawnHitEffect(x, y, color)
    )
    const noteLoad = withTimeout(this.noteManager.loadAssets(), 'Note Assets')

    return [crowdLoad, effectLoad, noteLoad]
  }

  /**
   * Finalizes manager initialization after assets are loaded.
   * @private
   */
  _finalizeInit() {
    if (this.isDisposed) return

    // Initialize managers now that assets are loaded
    this.crowdManager.init()
    this.effectManager.init()
    this.noteManager.init()
  }

  /**
   * Manually runs a single update frame, useful for testing without a real ticker.
   * @param {number} deltaMS - Time delta in milliseconds.
   */
  manualUpdate(deltaMS: number) {
    if (!this.app || this.isDisposed) return
    // @ts-expect-error PIXI ticker payload includes deltaMS; shape matches runtime use in handleTicker.
    this.handleTicker({ deltaMS })
  }

  /**
   * Handles ticker updates from Pixi.js.
   * Called by BaseStageController.handleTicker().
   * @param {number} deltaMS - Time delta.
   */
  update(deltaMS: number) {
    if (!this._canUpdate()) {
      return
    }

    const state = this.gameStateRef?.current

    if (!state || state.isGameOver) {
      return
    }
    const stageContainer = this.stageContainer
    if (!stageContainer) {
      return
    }
    const toxic = this.toxicFilterManager
    if (!toxic) {
      return
    }

    const elapsed = getGigTimeMs()

    toxic.update(state, elapsed, stageContainer)

    this.laneManager.update(state)
    this.crowdManager.update(
      state.combo ?? 0,
      state.isToxicMode ?? false,
      elapsed
    )
    this.noteManager.update(state, elapsed, this.laneManager.layout)
    this.effectManager.update(deltaMS)
  }

  /**
   * Checks if the controller is ready to update.
   * @returns {boolean} True if ready to update.
   * @private
   */
  _canUpdate() {
    return !!(
      this.app &&
      !this.isDisposed &&
      this.stageContainer &&
      this.laneManager &&
      this.crowdManager &&
      this.noteManager &&
      this.effectManager &&
      this.toxicFilterManager &&
      this.toxicFilterManager.isReady()
    )
  }

  /**
   * Disposes Pixi resources and removes the canvas.
   * @returns {void}
   */
  dispose() {
    this.noteManager?.dispose()
    this.effectManager?.dispose()
    this.laneManager?.dispose()
    this.crowdManager?.dispose()
    this.toxicFilterManager?.dispose()

    this.noteManager = null
    this.effectManager = null
    this.laneManager = null
    this.crowdManager = null
    this.toxicFilterManager = null

    if (this.stageContainer) {
      this.stageContainer.filters = null
      this.stageContainer.destroy({ children: true })
      this.stageContainer = null
    }

    super.dispose()
  }
}

/**
 * Factory for PixiStageController instances.
 * @param {object} params - Controller dependencies.
 * @returns {PixiStageController} Controller instance.
 */
export const createPixiStageController = (
  params: StageControllerOptions<RhythmGameRefState>
) => new PixiStageController(params)

import React from 'react'
import { BandHQ } from '../../ui/BandHQ'
import { QuestsModal } from '../../ui/QuestsModal'
import { ContrabandStash } from '../../ui/ContrabandStash'
import { PirateRadioModal } from '../../ui/PirateRadioModal'
import { MerchPressModal } from '../../ui/MerchPressModal'
import { BloodBankModal } from '../../ui/BloodBankModal'
import { DarkWebLeakModal } from '../../ui/DarkWebLeakModal'

export interface OverworldModalsProps {
  // Band HQ
  showHQ: boolean
  closeHQ: () => void

  // Quests
  showQuests: boolean
  questsProps: any // Ideally this should be properly typed, but avoiding structural changes

  // Stash
  showStash: boolean
  stashProps: any // Same as questsProps

  // Pirate Radio
  showPirateRadio: boolean
  closePirateRadio: () => void
  triggerBroadcast: () => void
  canBroadcast: boolean
  hasBroadcastedToday: boolean
  PIRATE_RADIO_CONFIG: any

  // Merch Press
  showMerchPress: boolean
  closeMerchPress: () => void
  triggerPress: () => void
  canPress: boolean
  merchPressConfig: any

  // Blood Bank
  showBloodBank: boolean
  closeBloodBank: () => void
  triggerDonate: () => void
  canDonate: boolean
  bloodBankConfig: any

  // Dark Web Leak
  showDarkWebLeak: boolean
  closeDarkWebLeak: () => void
  triggerLeak: () => void
  canDarkWebLeak: boolean
  hasLeakedToday: boolean
  DARK_WEB_LEAK_CONFIG: any
}

export const OverworldModals = React.memo(
  ({
    showHQ,
    closeHQ,
    showQuests,
    questsProps,
    showStash,
    stashProps,
    showPirateRadio,
    closePirateRadio,
    triggerBroadcast,
    canBroadcast,
    hasBroadcastedToday,
    PIRATE_RADIO_CONFIG,
    showMerchPress,
    closeMerchPress,
    triggerPress,
    canPress,
    merchPressConfig,
    showBloodBank,
    closeBloodBank,
    triggerDonate,
    canDonate,
    bloodBankConfig,
    showDarkWebLeak,
    closeDarkWebLeak,
    triggerLeak,
    canDarkWebLeak,
    hasLeakedToday,
    DARK_WEB_LEAK_CONFIG
  }: OverworldModalsProps) => {
    return (
      <>
        {showHQ && <BandHQ onClose={closeHQ} />}
        {showQuests && <QuestsModal {...questsProps} />}
        {showStash && <ContrabandStash {...stashProps} />}
        {showPirateRadio && (
          <PirateRadioModal
            onClose={closePirateRadio}
            onBroadcast={triggerBroadcast}
            canBroadcast={canBroadcast}
            hasBroadcastedToday={hasBroadcastedToday}
            config={PIRATE_RADIO_CONFIG}
          />
        )}
        {showMerchPress && (
          <MerchPressModal
            onClose={closeMerchPress}
            onPress={triggerPress}
            canPress={canPress}
            config={merchPressConfig}
          />
        )}
        {showBloodBank && (
          <BloodBankModal
            onClose={closeBloodBank}
            onDonate={triggerDonate}
            canDonate={canDonate}
            config={bloodBankConfig}
          />
        )}
        {showDarkWebLeak && (
          <DarkWebLeakModal
            onCancel={closeDarkWebLeak}
            onConfirm={triggerLeak}
            canLeak={canDarkWebLeak}
            hasLeakedToday={hasLeakedToday}
            config={DARK_WEB_LEAK_CONFIG}
          />
        )}
      </>
    )
  }
)

OverworldModals.displayName = 'OverworldModals'

import { Application, Container, Sprite, Texture } from 'pixi.js'
import { EffectTextureManager } from './EffectTextureManager'
import { EffectSprite, EffectSpritePool } from './EffectSpritePool'

export class EffectManager {
  static MAX_ACTIVE_EFFECTS = 50
  app: Application
  parentContainer: Container
  container: Container | null
  textureManager: EffectTextureManager
  activeEffects: Array<EffectSprite | null>
  effectCount: number
  headIndex: number
  tailIndex: number
  spritePool: EffectSpritePool

  /**
   * @param {Application} app
   * @param {Container} parentContainer
   */
  constructor(app: Application, parentContainer: Container) {
    this.app = app
    this.parentContainer = parentContainer
    this.container = null
    this.textureManager = new EffectTextureManager(app)

    // Use an array with index tracking to implement a fast Circular Buffer
    // This allows O(1) removals of the oldest effect without shifting.
    this.activeEffects = new Array(EffectManager.MAX_ACTIVE_EFFECTS)
    this.effectCount = 0
    this.headIndex = 0
    this.tailIndex = 0

    // Pool for Sprites (no longer need separate graphics pool)
    this.spritePool = new EffectSpritePool()
  }

  init(): void {
    this.container = new Container()
    this.parentContainer.addChild(this.container)
    this.spritePool.setContainer(this.container)
  }

  async loadAssets(): Promise<void> {
    await this.textureManager.loadAssets()
  }

  /**
   * Releases an effect sprite to the pool.
   * NOTE: This method must ONLY be used for effects NOT tracked in the circular buffer (activeEffects),
   * or the buffer state will become inconsistent.
   */
  releaseEffectToPool(effect: EffectSprite | null): void {
    this.spritePool.releaseSprite(effect)
  }

  _evictOldestEffect(): void {
    // O(1) removal of the oldest effect (which is always at headIndex)
    const oldest = this.activeEffects[this.headIndex]
    this.spritePool.releaseSprite(oldest)
    this.activeEffects[this.headIndex] = null

    this.headIndex = (this.headIndex + 1) % EffectManager.MAX_ACTIVE_EFFECTS
    this.effectCount--
  }

  spawnHitEffect(x: number, y: number, color: number): void {
    if (!this.container) return

    // Cap active effects using MAX_ACTIVE_EFFECTS
    if (this.effectCount >= EffectManager.MAX_ACTIVE_EFFECTS) {
      this._evictOldestEffect()
    }

    const texture = this.textureManager.resolveHitTexture(color)
    const effect = this.spritePool.getSprite(texture)

    effect.tint = color
    effect.x = x
    effect.y = y
    effect.alpha = 1
    effect.scale.set(0.5)
    effect.visible = true

    // Store animation state
    effect.life = 1.0 // 1.0 to 0.0

    this.container.addChild(effect)

    // Add to circular buffer
    this.activeEffects[this.tailIndex] = effect
    this.tailIndex = (this.tailIndex + 1) % EffectManager.MAX_ACTIVE_EFFECTS
    this.effectCount++
  }

  _handleDeadEffect(idx: number, i: number, count: number): number {
    // If it's the head (oldest), we can easily advance head
    if (i === 0) {
      this.headIndex = (this.headIndex + 1) % EffectManager.MAX_ACTIVE_EFFECTS
      this.effectCount--
      return count - 1
      // Don't increment i because the new head is now at "relative index 0"
    } else {
      // It died naturally but isn't the head. This shouldn't happen
      // because they decay uniformly, but if it does (e.g. edge case),
      // use swap-and-pop with the tail element to maintain density.

      // The actual tail index of the last valid element:
      const lastValidIdx =
        (this.headIndex + count - 1) % EffectManager.MAX_ACTIVE_EFFECTS
      const lastEffect = this.activeEffects[lastValidIdx]

      this.activeEffects[idx] = lastEffect
      this.activeEffects[lastValidIdx] = null

      this.tailIndex = lastValidIdx
      this.effectCount--
      return count - 1
      // Don't increment i, we need to process the swapped element
    }
  }

  update(deltaMS: number): void {
    const deltaSec = deltaMS / 1000
    const decay = deltaSec * 3

    // Iterate through the circular buffer
    let i = 0
    let count = this.effectCount

    while (i < count) {
      // Index relative to head
      const idx = (this.headIndex + i) % EffectManager.MAX_ACTIVE_EFFECTS
      const effect = this.activeEffects[idx]
      if (!effect) {
        i++
        continue
      }

      const newLife = effect.life - decay // Fade out speed
      effect.life = newLife

      if (newLife <= 0) {
        this.spritePool.releaseSprite(effect)
        this.activeEffects[idx] = null

        count = this._handleDeadEffect(idx, i, count)
      } else {
        effect.alpha = newLife
        effect.scale.set(0.5 + (1.0 - newLife) * 1.5) // Expand from 0.5 to 2.0
        i++
      }
    }
  }

  dispose(): void {
    this.activeEffects = new Array(EffectManager.MAX_ACTIVE_EFFECTS)
    this.effectCount = 0
    this.headIndex = 0
    this.tailIndex = 0

    this.spritePool.dispose()

    this.textureManager.dispose()

    if (this.container) {
      this.container.destroy({ children: true })
      this.container = null
    }
  }
}

import { Application, Container, Texture } from 'pixi.js'
import type { RefObject } from 'react'
import { handleError } from '../../utils/errorHandler'
import { calculateNoteY } from './utils'
import {
  NoteSpritePool,
  NOTE_CENTER_OFFSET,
  type NoteSprite
} from './NoteSpritePool'
import { NoteTextureManager, type NoteTextures } from './NoteTextureManager'

const NOTE_SPAWN_LEAD_MS = 2000

type StageLane = { color: number; renderX?: number }
type StageNote = {
  time: number
  visible: boolean
  hit: boolean
  laneIndex: number
}
type StageState = {
  notes: StageNote[]
  notesVersion?: number
  lanes: StageLane[]
  modifiers?: { noteJitter?: boolean }
  speed: number
}
type LaneLayout = { hitLineY?: number }
type ActiveNoteEntity = { note: StageNote; sprite: NoteSprite }

const getLaneRenderX = (lane: StageLane): number =>
  // RhythmGameRefState keeps renderX optional while lanes are being laid out.
  // Before layout completes, render notes at the left edge instead of crashing.
  lane.renderX ?? 0

export class NoteManager {
  app: Application
  parentContainer: Container
  gameStateRef: RefObject<StageState>
  onHit: ((x: number, y: number, color: number) => void) | null
  container: Container | null
  pool: NoteSpritePool | null
  activeEntities: ActiveNoteEntity[]
  nextRenderIndex: number
  lastNotesVersion: number | null
  textureManager: NoteTextureManager

  /**
   * @param {Application} app
   * @param {Container} parentContainer
   * @param {object} gameStateRef
   * @param {Function} onHit - Callback when a note is hit (x, y, color)
   */
  constructor(
    app: Application,
    parentContainer: Container,
    gameStateRef: RefObject<StageState>,
    onHit: ((x: number, y: number, color: number) => void) | null
  ) {
    this.app = app
    this.parentContainer = parentContainer
    this.gameStateRef = gameStateRef
    this.onHit = onHit
    this.container = null
    this.pool = null
    this.activeEntities = [] // Track active {note, sprite} pairs for fast iteration
    this.nextRenderIndex = 0
    this.lastNotesVersion = null // Tracks game-state notesVersion for song-transition resets
    this.textureManager = new NoteTextureManager()
  }

  init(): void {
    this.container = new Container()
    this.parentContainer.addChild(this.container)
    this.pool = new NoteSpritePool(this.container)
    // Pass loaded textures to the pool
    this.pool.noteTextures = this.textureManager.noteTextures
  }

  async loadAssets(): Promise<void> {
    await this.textureManager.loadAssets()
    if (this.pool) {
      this.pool.noteTextures = this.textureManager.noteTextures
    }
  }

  update(state: StageState, elapsed: number, laneLayout: LaneLayout): void {
    const targetY = laneLayout?.hitLineY ?? 0

    this._handleSongTransitions(state)
    this._spawnNewNotes(state, elapsed)
    this._updateActiveNotes(state, elapsed, targetY)
  }

  _handleSongTransitions(state: StageState): void {
    // Detect song transitions via the notesVersion counter that the audio hook
    // increments every time it replaces the notes array. This is more reliable
    // than the old elapsed < 100 heuristic which only worked for full restarts.
    const notesVersion = state.notesVersion ?? 0
    if (notesVersion !== this.lastNotesVersion) {
      this.lastNotesVersion = notesVersion
      this.nextRenderIndex = 0
      for (let i = 0; i < this.activeEntities.length; i++) {
        this.pool?.destroyNoteSprite(this.activeEntities[i]?.sprite)
      }
      this.activeEntities.length = 0
    }
  }

  _spawnNewNotes(state: StageState, elapsed: number): void {
    const notes = state.notes
    while (this.nextRenderIndex < notes.length) {
      const note = notes[this.nextRenderIndex]
      if (!note) break

      if (elapsed >= note.time - NOTE_SPAWN_LEAD_MS) {
        if (note.visible && !note.hit) {
          const lane = state.lanes[note.laneIndex]
          if (lane && this.pool && this.container) {
            const renderLane = { ...lane, renderX: getLaneRenderX(lane) }
            const sprite = this.pool.acquireSpriteFromPool(
              renderLane,
              note.laneIndex
            )
            this.container.addChild(sprite)
            this.activeEntities.push({ note, sprite })
          }
        }
        this.nextRenderIndex++
      } else {
        break
      }
    }
  }

  _updateActiveNotes(
    state: StageState,
    elapsed: number,
    targetY: number
  ): void {
    let writeIdx = 0
    for (let i = 0; i < this.activeEntities.length; i++) {
      const entity = this.activeEntities[i]
      if (!entity) continue
      const note = entity.note
      const sprite = entity.sprite

      if (note.hit) {
        const laneColor = state.lanes?.[note.laneIndex]?.color ?? 0xffffff
        if (this.onHit) {
          this.onHit(sprite.x, sprite.y, laneColor)
        }
        this.pool?.destroyNoteSprite(sprite)
        continue
      }

      if (!note.visible) {
        this.pool?.destroyNoteSprite(sprite)
        continue
      }

      const jitterOffset = state.modifiers?.noteJitter ? sprite.jitterOffset : 0

      sprite.y = calculateNoteY(elapsed, note.time, targetY, state.speed)

      // Unified positioning logic for both texture and fallback sprites
      // Fallback sprites (isFallback=true) do not jitter and are centered at renderX + 50
      // Normal sprites jitter and are also centered at renderX + 50
      const lane = state.lanes[note.laneIndex]
      if (!lane) {
        this.pool?.destroyNoteSprite(sprite)
        continue
      }
      sprite.x =
        getLaneRenderX(lane) +
        NOTE_CENTER_OFFSET +
        (sprite.isFallback ? 0 : jitterOffset)

      this.activeEntities[writeIdx++] = entity
    }

    // Trim the array to the actual number of active notes remaining
    this.activeEntities.length = writeIdx
  }

  dispose(): void {
    for (let i = 0; i < this.activeEntities.length; i++) {
      this.pool?.destroyNoteSprite(this.activeEntities[i]?.sprite)
    }
    this.activeEntities = []
    this.nextRenderIndex = 0
    this.lastNotesVersion = null

    this.textureManager.dispose()

    if (this.pool) {
      this.pool.dispose()
      this.pool = null
    }

    if (this.container) {
      this.container.destroy({ children: true })
      this.container = null
    }
  }
}

import { Container, Graphics, Sprite, Texture } from 'pixi.js'
import { EffectManager } from './EffectManager'

export class RoadiePlayerManager {
  playerContainer: Container | null
  playerSprite: Sprite | Graphics | null
  itemSprite: Sprite | null
  effectManager: EffectManager | null
  _flashTimeout: ReturnType<typeof setTimeout> | null
  lastDamage: number
  textures: {
    roadie: import('pixi.js').Texture | null
    items: Record<string, import('pixi.js').Texture | undefined>
  }
  colors: {
    bloodRed: number
    starWhite: number
    toxicGreen: number
  }

  constructor(
    textures: {
      roadie: import('pixi.js').Texture | null
      items: Record<string, import('pixi.js').Texture | undefined>
    },
    colors: {
      bloodRed: number
      starWhite: number
      toxicGreen: number
    }
  ) {
    this.playerContainer = null
    this.playerSprite = null
    this.itemSprite = null
    this.effectManager = null
    this._flashTimeout = null
    this.lastDamage = 0
    this.textures = textures
    this.colors = colors
  }

  setup(container: Container, cellW: number, cellH: number) {
    // Player Container (Groups body + item)
    this.playerContainer = new Container()
    container.addChild(this.playerContainer)

    // Player Sprite
    if (this.textures.roadie) {
      this.playerSprite = new Sprite(this.textures.roadie)
      this.playerSprite.anchor.set(0.5)
      // Scale to fit ~1 cell
      const playerScale =
        Math.min(
          cellW / this.textures.roadie.width,
          cellH / this.textures.roadie.height
        ) * 0.8
      this.playerSprite.scale.set(playerScale)
    } else {
      this.playerSprite = new Graphics()
      ;(this.playerSprite as Graphics).circle(0, 0, 20)
      ;(this.playerSprite as Graphics).fill(this.colors.toxicGreen)
    }
    this.playerContainer.addChild(this.playerSprite)

    // Item Sprite (Placeholder for now, visible only when carrying)
    this.itemSprite = new Sprite()
    this.itemSprite.anchor.set(0.5)
    this.itemSprite.y = -(cellH * 0.3) // Above head
    this.itemSprite.visible = false
    this.playerContainer.addChild(this.itemSprite)
  }

  setEffectManager(effectManager: EffectManager) {
    this.effectManager = effectManager
  }

  updatePlayerPosition(state: any, cellW: number, cellH: number) {
    if (this.playerContainer) {
      this.playerContainer.x = (state.playerPos.x + 0.5) * cellW
      this.playerContainer.y = (state.playerPos.y + 0.5) * cellH
    }
  }

  updateCarryingVisuals(state: any, cellW: number, cellH: number) {
    if (this.itemSprite && this.textures.items) {
      if (state.carrying) {
        this.itemSprite.visible = true
        // Set texture based on type
        const tex = this.textures.items[state.carrying.type]
        if (tex && tex.width > 0 && tex.height > 0) {
          this.itemSprite.texture = tex
          // Scale item to fit ~0.6 of a cell
          const itemScale =
            Math.min(cellW / tex.width, cellH / tex.height) * 0.6
          this.itemSprite.scale.set(itemScale)
        } else {
          this.itemSprite.texture = Texture.WHITE
          this.itemSprite.scale.set(0.3)
        }
      } else {
        this.itemSprite.visible = false
      }
    }
  }

  checkDamageTriggers(state: any) {
    if (state.equipmentDamage > this.lastDamage) {
      // Trigger Hit Effect
      const redColor = this.colors.bloodRed
      if (this.effectManager && this.playerContainer) {
        this.effectManager.spawnHitEffect(
          this.playerContainer.x,
          this.playerContainer.y,
          redColor
        )
      }
      this.lastDamage = state.equipmentDamage

      // Flash player
      if (this.playerSprite) {
        this.playerSprite.tint = redColor
        if (this._flashTimeout) clearTimeout(this._flashTimeout)
        this._flashTimeout = setTimeout(() => {
          if (this.playerSprite) this.playerSprite.tint = this.colors.starWhite
          this._flashTimeout = null
        }, 200)
      }
    }
  }

  dispose() {
    if (this._flashTimeout) {
      clearTimeout(this._flashTimeout)
      this._flashTimeout = null
    }
    if (this.playerSprite) {
      this.playerSprite.destroy()
    }
    if (this.itemSprite) {
      this.itemSprite.destroy()
    }
    if (this.playerContainer) {
      this.playerContainer.destroy({ children: true })
    }
    this.playerContainer = null
    this.playerSprite = null
    this.itemSprite = null
    this.effectManager = null
  }
}

import { Container, Graphics, Sprite, Texture } from 'pixi.js'
import { BaseStageController } from './BaseStageController'
import { RoadieTrafficManager } from './RoadieTrafficManager'
import { RoadiePlayerManager } from './RoadiePlayerManager'
import {
  ROADIE_GRID_WIDTH,
  ROADIE_GRID_HEIGHT
} from '../../hooks/minigames/constants'
import { EffectManager } from './EffectManager'
import { getPixiColorFromToken, loadTextures } from './utils'
import { logger } from '../../utils/logger'
import { IMG_PROMPTS, getGenImageUrl } from '../../utils/imageGen'
import { handleError, GameError } from '../../utils/errorHandler'
import { hashString } from '../../utils/stringUtils'

class RoadieStageController extends BaseStageController {
  effectManager: EffectManager | null
  textures: {
    roadie: import('pixi.js').Texture | null
    cars: import('pixi.js').Texture[]
    items: Record<string, import('pixi.js').Texture | undefined>
  }
  colors: {
    bloodRed: number
    starWhite: number
    toxicGreen: number
    roadColor: number
    grassColor: number
    venueColor: number
  }
  bgGraphics: Graphics | null
  trafficManager: RoadieTrafficManager | null
  playerManager: RoadiePlayerManager | null

  constructor(params: any) {
    super(params)
    this.effectManager = null
    this.trafficManager = null
    this.playerManager = null

    this.textures = {
      roadie: null,
      cars: [],
      items: {}
    }
    this.colors = {
      bloodRed: getPixiColorFromToken('--blood-red'),
      starWhite: getPixiColorFromToken('--star-white'),
      toxicGreen: getPixiColorFromToken('--toxic-green'),
      roadColor: getPixiColorFromToken('--void-black'),
      grassColor: getPixiColorFromToken('--roadie-grass'),
      venueColor: getPixiColorFromToken('--roadie-venue-blue')
    }
  }

  async setup() {
    // Draw Background Grid (Static)
    this.drawBackground()

    // Effect Manager
    this.effectManager = new EffectManager(this.app, this.container)
    this.effectManager.init()

    // Load Assets concurrently
    await Promise.all([this.loadAssets(), this.effectManager.loadAssets()])
    if (this.isDisposed) return

    const screenW = this.app.screen.width
    const screenH = this.app.screen.height
    const cellW = screenW / ROADIE_GRID_WIDTH
    const cellH = screenH / ROADIE_GRID_HEIGHT

    this.playerManager = new RoadiePlayerManager(this.textures, this.colors)
    this.playerManager.setup(this.container, cellW, cellH)
    if (this.effectManager) {
      this.playerManager.setEffectManager(this.effectManager)
    }

    this.trafficManager = new RoadieTrafficManager(
      this.container,
      this.textures,
      this.colors
    )
  }

  async loadAssets() {
    try {
      // URLs
      const urls = {
        roadie: getGenImageUrl(IMG_PROMPTS.MINIGAME_ROADIE_IDLE),
        carA: getGenImageUrl(IMG_PROMPTS.MINIGAME_CAR_A),
        carB: getGenImageUrl(IMG_PROMPTS.MINIGAME_CAR_B),
        carC: getGenImageUrl(IMG_PROMPTS.MINIGAME_CAR_C),
        amp: getGenImageUrl(IMG_PROMPTS.MINIGAME_ITEM_AMP),
        drums: getGenImageUrl(IMG_PROMPTS.MINIGAME_ITEM_DRUMS),
        guitar: getGenImageUrl(IMG_PROMPTS.MINIGAME_ITEM_GUITAR)
      }

      const loaded = (await loadTextures(urls, undefined)) as Record<
        keyof typeof urls,
        import('pixi.js').Texture | null
      >

      if (this.isDisposed) return

      this.textures.roadie = loaded.roadie
      const cars = []
      if (loaded.carA) cars.push(loaded.carA)
      if (loaded.carB) cars.push(loaded.carB)
      if (loaded.carC) cars.push(loaded.carC)
      this.textures.cars = cars
      this.textures.items = {
        AMP: loaded.amp,
        DRUMS: loaded.drums,
        GUITAR: loaded.guitar
      }
    } catch (e) {
      handleError(
        new GameError('Asset load failed', {
          context: { originalError: e instanceof Error ? e : String(e) }
        })
      )
    }
  }

  draw() {
    this.drawBackground()
  }

  drawBackground() {
    if (this.bgGraphics) {
      this.container.removeChild(this.bgGraphics)
      this.bgGraphics.destroy()
    }

    const g = new Graphics()
    this.bgGraphics = g

    // Use screen width for better drawing
    const width = this.app ? this.app.screen.width : 2000
    const height = this.app ? this.app.screen.height : 600
    const cellH = height / ROADIE_GRID_HEIGHT // dynamic height

    // Start zone (row 0)
    g.rect(0, 0, width, cellH)
    g.fill(this.colors.grassColor)

    // Road
    g.rect(0, cellH, width, cellH * 6)
    g.fill(this.colors.roadColor)

    // Venue zone (row 7)
    g.rect(0, cellH * 7, width, cellH)
    g.fill(this.colors.venueColor)

    // Stripes
    for (let r = 2; r <= 6; r++) {
      for (let x = 0; x < width; x += 100) {
        g.rect(x, r * cellH - 2, 60, 4)
        g.fill(this.colors.starWhite)
      }
    }

    // Add at index 0 (bottom)
    this.container.addChildAt(g, 0)
  }

  update(dt: any) {
    if (this.isDisposed || !this.app || !this.playerManager?.playerContainer)
      return

    if (this.effectManager) this.effectManager.update(dt)

    if (!this.gameStateRef.current) return
    const state = this.gameStateRef.current

    if (!state.playerPos) return

    const screenW = this.app.screen.width
    const screenH = this.app.screen.height
    const cellW = screenW / ROADIE_GRID_WIDTH
    const cellH = screenH / ROADIE_GRID_HEIGHT

    if (this.playerManager) {
      this.playerManager.updatePlayerPosition(state, cellW, cellH)
      this.playerManager.updateCarryingVisuals(state, cellW, cellH)
      this.playerManager.checkDamageTriggers(state)
    }

    if (this.trafficManager) {
      this.trafficManager.renderTraffic(state, cellW, cellH)
      this.trafficManager.cleanupTraffic()
    }
  }

  dispose() {
    if (this.playerManager) {
      this.playerManager.dispose()
      this.playerManager = null
    }

    if (this.trafficManager) {
      this.trafficManager.dispose()
      this.trafficManager = null
    }

    if (this.effectManager) {
      this.effectManager.dispose()
      this.effectManager = null
    }

    super.dispose()
  }
}

export const createRoadieStageController = (params: any) =>
  new RoadieStageController(params)

import { Container, Graphics, Sprite, Texture } from 'pixi.js'
import { logger } from '../../utils/logger'
import { hashString } from '../../utils/stringUtils'

export class RoadieTrafficManager {
  container: Container
  textures: {
    cars: import('pixi.js').Texture[]
  }
  colors: {
    bloodRed: number
  }
  carSprites: Map<string | number, Sprite | Graphics>
  currentIds: Set<string | number>

  constructor(
    container: Container,
    textures: { cars: import('pixi.js').Texture[] },
    colors: { bloodRed: number }
  ) {
    this.container = container
    this.textures = textures
    this.colors = colors
    this.carSprites = new Map()
    this.currentIds = new Set() // Reuse Set to avoid GC
  }

  _getOrCreateCarSprite(car: any) {
    let sprite = this.carSprites.get(car.id)
    if (sprite) return sprite

    if (this.textures.cars.length > 0) {
      let textureHash = car.textureHash
      if (!Number.isFinite(textureHash)) {
        textureHash = hashString(
          String(car.id ?? `car_${car.row}_${car.speed}`)
        )
      }
      const texIndex =
        Math.floor(Math.abs(textureHash)) % this.textures.cars.length
      sprite = new Sprite(this.textures.cars[texIndex])

      sprite.anchor.set(0.5)
    } else {
      sprite = new Graphics()
      ;(sprite as Graphics).rect(-30, -20, 60, 40)
      ;(sprite as Graphics).fill(this.colors.bloodRed)
    }

    this.container.addChild(sprite)
    this.carSprites.set(car.id, sprite)
    return sprite
  }

  renderTraffic(state: any, cellW: any, cellH: any) {
    if (!Array.isArray(state.traffic)) return

    this.currentIds.clear()
    for (const car of state.traffic) {
      this.currentIds.add(car.id)
      const sprite = this._getOrCreateCarSprite(car)

      sprite.x = (car.x + car.width / 2) * cellW
      sprite.y = (car.row + 0.5) * cellH

      // Flip if moving left
      if (car.speed < 0) {
        sprite.scale.x = -Math.abs(sprite.scale.x)
      } else {
        sprite.scale.x = Math.abs(sprite.scale.x)
      }

      // Adjust Scale if texture — constrain both width AND height
      if (sprite instanceof Sprite && (sprite as Sprite).texture?.width > 0) {
        const texSprite = sprite as Sprite
        const targetW = car.width * cellW
        const targetH = cellH * 0.7
        const scale = Math.min(
          targetW / texSprite.texture.width,
          targetH / texSprite.texture.height
        )
        sprite.scale.set(
          Math.abs(scale) * Math.sign(sprite.scale.x),
          Math.abs(scale)
        )
      } else {
        // Fallback or Graphics
        sprite.width = car.width * cellW
        sprite.height = cellH * 0.7
      }
    }
  }

  cleanupTraffic() {
    if (this.carSprites && this.carSprites.size > 0) {
      for (const id of this.carSprites.keys()) {
        if (!this.currentIds.has(id)) {
          const sprite = this.carSprites.get(id)
          if (!sprite) continue

          try {
            this.container.removeChild(sprite)
          } catch (error) {
            logger.error(
              'RoadieTrafficManager',
              `Error removing sprite from container for id ${id}:`,
              error
            )
          }

          try {
            sprite.destroy()
          } catch (error) {
            logger.error(
              'RoadieTrafficManager',
              `Error destroying sprite for id ${id}:`,
              error
            )
          } finally {
            this.carSprites.delete(id)
          }
        }
      }
    }
  }

  dispose() {
    // Clean up car sprites explicitly
    if (this.carSprites) {
      for (const sprite of this.carSprites.values()) {
        sprite.destroy()
      }
      this.carSprites.clear()
    }
  }
}

import { Container, Graphics, Sprite, Texture } from 'pixi.js'
import { EffectManager } from './EffectManager'

export class TourbusObstacleManager {
  container: Container
  effectManager: EffectManager
  textures: {
    rock: Texture | null
    barrier: Texture | null
    fuel: Texture | null
  }
  colors: {
    warningYellow: number
    bloodRed: number
    toxicGreen: number
  }
  obstacleMap: Map<
    string | number,
    (Sprite | Graphics) & { hasExploded?: boolean }
  >
  currentIds: Set<string | number>

  constructor(
    container: Container,
    effectManager: EffectManager,
    textures: {
      rock: Texture | null
      barrier: Texture | null
      fuel: Texture | null
    },
    colors: {
      warningYellow: number
      bloodRed: number
      toxicGreen: number
    }
  ) {
    this.container = container
    this.effectManager = effectManager
    this.textures = textures
    this.colors = colors

    this.obstacleMap = new Map()
    this.currentIds = new Set()
  }

  updateObstacles(state: any, height: number, laneWidth: number) {
    this.currentIds.clear()

    for (let i = 0, len = state.obstacles.length; i < len; i++) {
      const obs = state.obstacles[i]
      this.currentIds.add(obs.id)
      let sprite = this.obstacleMap.get(obs.id)

      if (!sprite) {
        // Choose texture
        let tex = null
        if (obs.type === 'FUEL') tex = this.textures.fuel
        else if (obs.type === 'OBSTACLE') tex = this.textures.rock // Randomize?

        if (tex) {
          sprite = new Sprite(tex)
          sprite.anchor.set(0.5)
          // Scale to fit lane width AND a max height
          const targetW = laneWidth * 0.4
          const targetH = height * 0.15
          const scale = Math.min(targetW / tex.width, targetH / tex.height)
          sprite.scale.set(scale)
        } else {
          sprite = new Graphics()
          if (obs.type === 'FUEL') {
            sprite.circle(0, 0, 20)
            sprite.fill(this.colors.warningYellow)
          } else {
            sprite.rect(-25, -25, 50, 50)
            sprite.fill(this.colors.bloodRed)
          }
        }

        // Custom property to track explosion state
        sprite.hasExploded = false

        this.container.addChild(sprite)
        this.obstacleMap.set(obs.id, sprite)
      } else if (!obs.collided) {
        sprite.hasExploded = false
        sprite.alpha = 1
      }

      // Update position
      const x = obs.lane * laneWidth + laneWidth / 2
      const y = (obs.y / 100) * height
      sprite.x = x
      sprite.y = y

      // Visual feedback for collision
      if (obs.collided) {
        sprite.alpha = 0.5

        if (!sprite.hasExploded) {
          sprite.hasExploded = true
          if (obs.type === 'OBSTACLE') {
            this.effectManager.spawnHitEffect(x, y, this.colors.bloodRed) // Red explosion
          } else if (obs.type === 'FUEL') {
            this.effectManager.spawnHitEffect(x, y, this.colors.toxicGreen) // Green sparkle
          }
        }
      } else {
        sprite.hasExploded = false
        sprite.alpha = 1
      }
    }
  }

  cleanupObstacles() {
    // Performance optimization: Iterate over the Map's keys instead of entries to prevent
    // per-frame garbage collection pauses caused by allocating [id, sprite] arrays.
    for (const id of this.obstacleMap.keys()) {
      if (!this.currentIds.has(id)) {
        const sprite = this.obstacleMap.get(id)
        if (sprite) sprite.destroy() // PixiJS automatically removes from parent
        this.obstacleMap.delete(id)
      }
    }
  }

  dispose() {
    if (this.obstacleMap) {
      for (const sprite of this.obstacleMap.values()) {
        sprite.destroy()
      }
      this.obstacleMap.clear()
    }
    if (this.currentIds) {
      this.currentIds.clear()
    }
  }
}

import { Container, Graphics, Sprite, TilingSprite } from 'pixi.js'
import { BaseStageController } from './BaseStageController'
import { EffectManager } from './EffectManager'
import { TourbusObstacleManager } from './TourbusObstacleManager'
import { getPixiColorFromToken, loadTextures } from './utils'
import { logger } from '../../utils/logger'
import { IMG_PROMPTS, getGenImageUrl } from '../../utils/imageGen'
import {
  TOURBUS_LANE_COUNT,
  TOURBUS_BUS_Y_PERCENT,
  TOURBUS_BUS_HEIGHT_PERCENT
} from '../../hooks/minigames/constants'

class TourbusStageController extends BaseStageController {
  [key: string]: any
  constructor(params: any) {
    super(params)
    this.busSprite = null
    this.laneWidth = 0
    this.roadContainer = null
    this.obstacleContainer = null
    this.effectManager = null
    this.roadStripes = null // TilingSprite for road

    this.obstacleManager = null

    // Animation state
    this.wobbleTime = 0

    // Textures
    this.textures = {
      bus: null,
      road: null,
      rock: null,
      barrier: null,
      fuel: null
    }

    this.colors = {
      warningYellow: getPixiColorFromToken('--warning-yellow'),
      bloodRed: getPixiColorFromToken('--blood-red'),
      toxicGreen: getPixiColorFromToken('--toxic-green')
    }
  }

  async setup() {
    // Setup Layers
    this.roadContainer = new Container()
    this.obstacleContainer = new Container()
    this.container.addChild(this.roadContainer)
    this.container.addChild(this.obstacleContainer)

    // Initialize Effect Manager (on top of obstacles)
    this.effectManager = new EffectManager(this.app, this.container)
    this.effectManager.init()

    this.obstacleManager = new TourbusObstacleManager(
      this.obstacleContainer,
      this.effectManager,
      this.textures,
      this.colors
    )

    // Load Assets
    await this.loadAssets()
    await this.effectManager.loadAssets()

    // Initial Draw
    this.drawRoad()
    this.createBus()
  }

  async loadAssets() {
    try {
      // Generate URLs
      const urls = {
        bus: getGenImageUrl(IMG_PROMPTS.ICON_VAN),
        road: getGenImageUrl(IMG_PROMPTS.MINIGAME_ROAD),
        rock: getGenImageUrl(IMG_PROMPTS.MINIGAME_OBSTACLE_ROCK),
        barrier: getGenImageUrl(IMG_PROMPTS.MINIGAME_OBSTACLE_BARRIER),
        fuel: getGenImageUrl(IMG_PROMPTS.MINIGAME_FUEL)
      }

      const loaded = (await loadTextures(urls, undefined)) as Record<
        keyof typeof urls,
        import('pixi.js').Texture | null
      >

      const keys = Object.keys(loaded)
      for (let i = 0, len = keys.length; i < len; i++) {
        const key = keys[i]
        if (loaded[key]) this.textures[key] = loaded[key]
      }
    } catch (e) {
      logger.warn('TourbusStageController', 'Failed to load assets', e)
    }
  }

  draw() {
    this.drawRoad()
  }

  drawRoad() {
    const width = this.app.screen.width
    const height = this.app.screen.height
    this.laneWidth = width / TOURBUS_LANE_COUNT

    // Clear previous
    const children = this.roadContainer.removeChildren()
    for (let i = 0, len = children.length; i < len; i++) {
      children[i].destroy()
    }

    // Use TilingSprite if texture loaded AND source is valid, else Graphics fallback.
    // Image-element textures may have sources that crash TilingSprite (_resolution null).
    const roadTex = this.textures.road
    const isRoadTexValid = roadTex?.source && !roadTex.source.destroyed

    if (isRoadTexValid) {
      this.roadStripes = new TilingSprite({
        texture: roadTex,
        width,
        height
      })
      this.roadContainer.addChild(this.roadStripes)
    } else {
      this.roadStripes = null
      const bg = new Graphics()
      bg.rect(0, 0, width, height)
      bg.fill(getPixiColorFromToken('--void-black'))
      this.roadContainer.addChild(bg)

      // Draw lane dividers
      for (let i = 1; i < TOURBUS_LANE_COUNT; i++) {
        const line = new Graphics()
        line.rect(i * this.laneWidth - 2, 0, 4, height)
        line.fill({ color: getPixiColorFromToken('--ash-gray'), alpha: 0.3 })
        this.roadContainer.addChild(line)
      }
    }
  }

  createBus() {
    const height = this.app.screen.height

    if (this.textures.bus) {
      this.busSprite = new Sprite(this.textures.bus)
      this.busSprite.anchor.set(0.5, 1)
    } else {
      // Fallback
      const g = new Graphics()
      g.rect(-25, -80, 50, 80)
      g.fill(getPixiColorFromToken('--toxic-green'))
      this.busSprite = g
    }
    // Scale bus to fit lane width AND a max height
    const targetW = this.laneWidth * 0.6
    // Visual height slightly larger than collision box for aesthetics
    const targetH = height * ((TOURBUS_BUS_HEIGHT_PERCENT + 5) / 100)
    const texW = this.busSprite.texture?.width || this.busSprite.width || 60
    const texH = this.busSprite.texture?.height || this.busSprite.height || 80
    const busScale = Math.min(targetW / texW, targetH / texH)
    this.busSprite.scale.set(busScale)

    this.container.addChild(this.busSprite)
  }

  _updateBusPosition(state: any, dt: any, height: any) {
    if (this.busSprite) {
      const targetX = state.busLane * this.laneWidth + this.laneWidth / 2

      // Frame-independent Lerp
      // Using exponential decay: lerp(a, b, 1 - exp(-decay * dt))
      // Decay factor ~10 for snappy movement
      const dtSeconds = dt / 1000
      const lerpFactor = 1 - Math.exp(-10 * dtSeconds)

      this.busSprite.x += (targetX - this.busSprite.x) * lerpFactor
      // Position bottom of bus at bottom of collision box
      this.busSprite.y =
        height * ((TOURBUS_BUS_Y_PERCENT + TOURBUS_BUS_HEIGHT_PERCENT) / 100)

      // Wobble effect based on accumulated deterministic time
      // Wrap at the exact period of sin(x/100) to prevent float precision loss on long sessions
      this.wobbleTime = (this.wobbleTime + dt) % (Math.PI * 2 * 100)
      this.busSprite.rotation = Math.sin(this.wobbleTime / 100) * 0.05
    }
  }

  _updateRoadScroll(state: any, dt: any, height: any) {
    if (this.roadStripes) {
      // Speed is relative units per ms.
      // Let's say speed 0.05 => 50 units per sec.
      // We need pixel speed.
      // Height is 100 units. So 1 unit = height/100 pixels.
      const pixelSpeed = state.speed * (height / 100) * dt
      this.roadStripes.tilePosition.y += pixelSpeed
    }
  }

  update(dt: any) {
    if (this.effectManager) this.effectManager.update(dt)

    const state = this.gameStateRef.current
    if (!state) return

    const height = this.app.screen.height

    this._updateRoadScroll(state, dt, height)
    this._updateBusPosition(state, dt, height)
    if (this.obstacleManager) {
      this.obstacleManager.updateObstacles(state, height, this.laneWidth)
      this.obstacleManager.cleanupObstacles()
    }
  }

  dispose() {
    if (this.effectManager) {
      this.effectManager.dispose()
      this.effectManager = null
    }

    if (this.obstacleManager) {
      this.obstacleManager.dispose()
      this.obstacleManager = null
    }

    super.dispose()
  }
}

export const createTourbusStageController = (params: any) =>
  new TourbusStageController(params)

import { ColorMatrixFilter, Container } from 'pixi.js'

/**
 * Manages toxic mode filter effects for the stage.
 */
export class ToxicFilterManager {
  colorMatrix: ColorMatrixFilter | null
  toxicFilters: ColorMatrixFilter[] | null
  isToxicActive: boolean
  constructor() {
    this.isToxicActive = false
    this.colorMatrix = new ColorMatrixFilter()
    this.toxicFilters = [this.colorMatrix]
  }

  /**
   * Updates toxic mode filter effects based on game state.
   * @param {object} state - The game state.
   * @param {number} elapsed - The elapsed gig time.
   */
  update(state: any, elapsed: number, stageContainer: Container): void {
    if (state.isToxicMode) {
      if (this.colorMatrix) {
        this.colorMatrix.hue(Math.sin(elapsed / 100) * 180, false)
      }
      if (!this.isToxicActive && stageContainer) {
        stageContainer.filters = this.toxicFilters
        this.isToxicActive = true
      }
    } else {
      if (this.isToxicActive && stageContainer) {
        stageContainer.filters = null
        this.isToxicActive = false
      }
    }
  }

  /**
   * Checks if the manager is ready for updates.
   * @returns {boolean}
   */
  isReady(): boolean {
    return !!this.toxicFilters
  }

  /**
   * Disposes Pixi resources related to toxic filters.
   */
  dispose(): void {
    if (this.colorMatrix) {
      this.colorMatrix.destroy()
      this.colorMatrix = null
    }

    this.toxicFilters = null
  }
}

import {
  useReducer,
  useRef,
  useMemo,
  useState,
  type MutableRefObject
} from 'react'
