              >
                {displayMoney}
              </span>
            </div>
            <div className='loc-row'>
              <span style={{ color: 'var(--color-toxic-green)' }}>⬡</span>
              <span>
                {t('ui:ui.day', { defaultValue: 'Day' })} {player.day ?? 1} —{' '}
                {locationName}
              </span>
            </div>
            <div className='van-stats'>
              <div className='van-row'>
                <span
                  className='van-icon'
                  style={{
                    color: fuelLow
                      ? 'var(--color-blood-red)'
                      : 'var(--color-warning-yellow)'
                  }}
                >
                  ⛽
                </span>
                <div className='mini-track'>
                  <div
                    className='mini-fill'
                    style={{
                      width: vanFuel !== undefined ? `${vanFuel}%` : '0%',
                      background: fuelLow
                        ? 'var(--color-blood-red)'
                        : 'var(--color-warning-yellow)'
                    }}
                  />
                </div>
                <span
                  className='mini-num'
                  style={{
                    color: fuelLow ? 'var(--color-blood-red)' : undefined
                  }}
                >
                  {vanFuel !== undefined
                    ? vanFuel
                    : t('ui:overworld.notAvailable', { defaultValue: 'N/A' })}
                </span>
              </div>
              <div className='van-row'>
                <span
                  className='van-icon'
