import { memo, useState, useRef, useEffect, useId, useCallback } from 'react'
import type { MouseEvent } from 'react'
import PropTypes from 'prop-types'
import { useTranslation } from 'react-i18next'

/**
 * ToggleSwitch - A standardized toggle switch for binary options.
 * @module ToggleSwitch
 * @param {Object} props
 * @param {boolean} props.isOn - Current state.
 * @param {Function} props.onToggle - Callback function.
 * @param {string} props.ariaLabel - Accessible label.
 * @param {string} [props.className] - Additional CSS classes.
 */
type ToggleSwitchProps = {
  isOn: boolean
  onToggle: () => void
  ariaLabel: string
  className?: string
}

const ToggleSwitchComponent = ({
  isOn,
  onToggle,
  ariaLabel,
  className = ''
}: ToggleSwitchProps) => {
  const { t } = useTranslation()
  const labelId = useId()
  const [isGlitching, setIsGlitching] = useState(false)
  const glitchTimerRef = useRef<number | null>(null)

  const handleToggle = useCallback(() => {
    setIsGlitching(true)
    if (glitchTimerRef.current) {
      window.clearTimeout(glitchTimerRef.current)
    }
    glitchTimerRef.current = window.setTimeout(() => setIsGlitching(false), 150)
    onToggle()
  }, [onToggle])

  useEffect(() => {
    return () => {
      if (glitchTimerRef.current) {
        clearTimeout(glitchTimerRef.current)
      }
    }
  }, [])

  return (
    <div
      className={`flex items-center justify-between w-full max-w-sm border border-toxic-green/30 p-3 bg-void-black ${className}`}
    >
      <span
        id={labelId}
        className='text-sm font-bold tracking-widest uppercase'
      >
        {ariaLabel}
      </span>
      <button
        type='button'
        onClick={handleToggle}
        className={`relative w-16 h-8 border-2 border-toxic-green flex items-center p-1 transition-colors duration-75 cursor-pointer focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-toxic-green focus-visible:ring-offset-2 focus-visible:ring-offset-void-black ${isGlitching ? 'translate-x-[1px] translate-y-[1px]' : ''}`}
        aria-checked={isOn}
        role='switch'
        {...(labelId
          ? { 'aria-labelledby': labelId }
          : { 'aria-label': ariaLabel })}
      >
        <div
          className={`w-full h-full absolute inset-0 bg-toxic-green transition-opacity duration-150 ${isOn ? 'opacity-20' : 'opacity-0'}`}
        ></div>
        <div
          className={`w-5 h-full bg-toxic-green transition-transform duration-100 z-10 ${isOn ? 'translate-x-8' : 'translate-x-0'}`}
        >
          <div className='w-[2px] h-full bg-void-black mx-auto opacity-50'></div>
        </div>
        <span
          className={`absolute text-[10px] font-bold z-0 ${isOn ? 'left-2 text-toxic-green' : 'right-2 text-toxic-green/50'}`}
        >
          {isOn ? t('ui:toggle.on') : t('ui:toggle.off')}
        </span>
      </button>
    </div>
  )
}

export const ToggleSwitch = memo(ToggleSwitchComponent)
ToggleSwitch.displayName = 'ToggleSwitch'

ToggleSwitch.propTypes = {
  isOn: PropTypes.bool.isRequired,
  onToggle: PropTypes.func.isRequired,
  ariaLabel: PropTypes.string.isRequired,
  className: PropTypes.string
}

import React, {
  useState,
  useId,
  cloneElement,
  isValidElement,
  useCallback
} from 'react'
import { logger } from '../../utils/logger'
import PropTypes from 'prop-types'
import type { ReactElement, ReactNode, SyntheticEvent } from 'react'

/**
 * Tooltip - Displays a floating tooltip on hover.
 * @param {Object} props
 * @param {React.ReactElement} props.children - The trigger element. Must be a valid React element.
 * @param {React.ReactNode} props.content - The tooltip content.
 * @param {string} [props.className] - Additional CSS classes for the container.
 */
export const Tooltip = ({
  children,
  content,
  className = ''
}: {
  children: ReactElement
  content: ReactNode
  className?: string
}) => {
  const [isVisible, setIsVisible] = useState(false)
  const tooltipId = useId()

  const child = children as ReactElement & { props: Record<string, unknown> }
  const childProps = child.props as Record<string, unknown>

  const isDisabled =
    Boolean(childProps.disabled) ||
    childProps['aria-disabled'] === true ||
    childProps['aria-disabled'] === 'true' ||
    (typeof childProps.className === 'string' &&
      (childProps.className as string)
        .split(' ')
        .includes('pointer-events-none')) ||
    (childProps.style &&
      (childProps.style as Record<string, unknown>).pointerEvents === 'none')

  const handleMouseEnter = useCallback(
    (e: SyntheticEvent) => {
      setIsVisible(true)
      const fn = childProps.onMouseEnter
      if (!isDisabled && typeof fn === 'function')
        (fn as (...args: unknown[]) => void)(e)
    },
    [childProps, isDisabled]
  )

  const handleMouseLeave = useCallback(
    (e: SyntheticEvent) => {
      setIsVisible(false)
      const fn = childProps.onMouseLeave
      if (!isDisabled && typeof fn === 'function')
        (fn as (...args: unknown[]) => void)(e)
    },
    [childProps, isDisabled]
  )

  const handleFocus = useCallback(
    (e: SyntheticEvent) => {
      setIsVisible(true)
      const fn = childProps.onFocus
      if (!isDisabled && typeof fn === 'function')
        (fn as (...args: unknown[]) => void)(e)
    },
    [childProps, isDisabled]
  )

  const handleBlur = useCallback(
    (e: SyntheticEvent) => {
      setIsVisible(false)
      const fn = childProps.onBlur
      if (!isDisabled && typeof fn === 'function')
        (fn as (...args: unknown[]) => void)(e)
    },
    [childProps, isDisabled]
  )

  const isValid = isValidElement(children)
  const isFragment = children && (children as any).type === React.Fragment

  React.useEffect(() => {
    if (!isValid) {
      logger.warn(
        'Tooltip',
        'Tooltip children must be a single valid React element.'
      )
    } else if (isFragment) {
      logger.warn(
        'Tooltip',
        'Tooltip children must be a single valid React element and not a Fragment.'
      )
    }
  }, [isValid, isFragment])

  if (!isValid || isFragment) {
    return children
  }

  const computedAriaDescribedBy = (() => {
    const existing = childProps['aria-describedby'] as string | undefined
    if (!isVisible) return existing
    if (!existing) return tooltipId
    const ids = existing.split(' ').filter(Boolean)
    if (!ids.includes(tooltipId)) ids.push(tooltipId)
    return ids.join(' ')
  })()

  const isFullWidth =
    typeof childProps.className === 'string' &&
    (childProps.className as string).split(' ').includes('w-full')

  const trigger = isDisabled ? (
    <span
      className={`inline-block ${isFullWidth ? 'w-full' : ''}`}
      tabIndex={0}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      onFocus={handleFocus}
      onBlur={handleBlur}
      aria-describedby={computedAriaDescribedBy}
    >
      {children}
    </span>
  ) : (
    // eslint-disable-next-line @eslint-react/no-clone-element
    cloneElement(
      children as ReactElement<any, any>,
      {
        onMouseEnter: handleMouseEnter,
        onMouseLeave: handleMouseLeave,
        onFocus: handleFocus,
        onBlur: handleBlur,
        'aria-describedby': computedAriaDescribedBy
      } as any
    )
  )

  return (
    <div
      className={`${isFullWidth ? 'block w-full' : 'inline-block'} ${className?.split(/\s+/).includes('absolute') ? '' : 'relative'} ${className}`}
    >
      {trigger}
      {isVisible && (
        <div
          id={tooltipId}
          role='tooltip'
          className='pointer-events-none absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-48 p-2 bg-void-black border border-ash-gray shadow-lg z-50 text-xs text-star-white'
        >
          {content}
        </div>
      )}
    </div>
  )
}

Tooltip.propTypes = {
  children: PropTypes.node.isRequired,
  content: PropTypes.node.isRequired,
  className: PropTypes.string
}

import { logger } from './logger'
import { handleError } from './errorHandler'
import { GAME_PHASES } from '../context/gameConstants'
import {
  clampMemberStamina,
  clampMemberMood,
  clampPlayerFame,
  calculateFameLevel,
  clampBandHarmony,
  BALANCE_CONSTANTS
} from './gameStateUtils'
import { secureRandom } from './crypto'
import i18n from '../i18n'

/**
 * Shared logic for handling arrival at a map node.
 * This can be used by both the legacy travel system and the new arrival logic hook.
 *
 * @param {object} params
 * @param {object} params.node - The node being arrived at.
 * @param {object} params.band - Current band state.
 * @param {object} params.player - Current player state (inventory, stats, etc.).
 * @param {Function} params.updateBand - Function to update band state.
 * @param {Function} params.updatePlayer - Function to update player state (handles side effects).
 * @param {Function} params.triggerEvent - Function to trigger events.
 * @param {Function} params.startGig - Function to start a gig.
 * @param {Function} params.addToast - Function to show notifications.
 * @param {Function} [params.changeScene] - Function to change scene (fallback).
 * @param {Function} [params.onShowHQ] - Optional callback to show HQ (for START node).
 * @param {boolean} [params.eventAlreadyActive=false] - Whether an event is already active (to prevent stacking).
 * @param {Function} [params.rng=secureRandom] - RNG function for probabilistic outcomes.
 */
/**
 * Calculates new harmony value if band has harmony regen active.
 * @param {object} band - The current band state.
 * @returns {number|null} The new harmony value, or null if regen is not applicable.
 */
export const processHarmonyRegen = (band: any): number | null => {
  if (band?.harmonyRegenTravel) {
    return clampBandHarmony((band.harmony ?? 0) + 5)
  }
  return null
}

/**
 * Checks if the current node is a gig node.
 * @param {object} node - The current node.
 * @returns {boolean} True if the node is a GIG, FESTIVAL, or FINALE.
 */
export const isGigNode = (node: any): boolean => {
  return (
    node?.type === 'GIG' || node?.type === 'FESTIVAL' || node?.type === 'FINALE'
  )
}

/**
 * Triggers travel events if applicable for the current node.
 * @param {object} node - The current node.
 * @param {Function} triggerEvent - The function to trigger events.
 * @returns {boolean} True if a travel event was triggered.
 */
export const processTravelEvents = (
  node: any,
  triggerEvent: (a: string, b?: string) => boolean
): boolean => {
  if (isGigNode(node)) {
    return false
  }

  let travelEventActive = triggerEvent('transport', 'travel')
  if (!travelEventActive) {
    travelEventActive = triggerEvent('band', 'travel')
  }
  return travelEventActive
}

type HandleNodeArrivalParams = {
  node: any
  band: any
  player: any
  updateBand: (p: any) => void
  updatePlayer: (p: any) => void
  triggerEvent: (a: string, b?: string) => boolean
  startGig: (venue: any) => void
  addToast: (msg: string, level?: string) => void
  changeScene?: (scene: string) => void
  onShowHQ?: () => void
  eventAlreadyActive?: boolean
  rng?: () => number
}

export const handleNodeArrival = (params: HandleNodeArrivalParams) => {
  const {
    node,
    band,
    player,
    updateBand,
    updatePlayer,
    triggerEvent,
    startGig,
    addToast,
    changeScene,
    onShowHQ,
    eventAlreadyActive = false,
    rng = secureRandom
  } = params
  switch (node.type) {
    case 'REST_STOP': {
      const members = band?.members ?? []
      const newMembers = new Array(members.length)
      for (let i = 0; i < members.length; i++) {
        const m = members[i]
        const newStamina = clampMemberStamina(m.stamina + 20, m.staminaMax)
        const newMood = clampMemberMood(m.mood + 10)
        newMembers[i] = {
          ...m,
          stamina: newStamina,
          mood: newMood
        }
      }
      updateBand({ members: newMembers })
      addToast(
        i18n.t('ui:arrival.restedAtStop', {
          defaultValue: 'Rested at stop. Band feels better.'
        }),
        'success'
      )
      break
    }
    case 'SPECIAL': {
      if (!eventAlreadyActive) {
        const specialEvent = triggerEvent('special')
        if (!specialEvent) {
          addToast(
            i18n.t('ui:arrival.specialNothingHappened', {
              defaultValue: 'A mysterious place, but nothing happened.'
            }),
            'info'
          )
        }
      }
      break
    }
    case 'START': {
      if (onShowHQ) onShowHQ()
      addToast(
        i18n.t('ui:arrival.homeSweetHome', {
          defaultValue: 'Home Sweet Home.'
        }),
        'success'
      )
      break
    }
    case 'FESTIVAL':
    case 'FINALE':
    case 'GIG': {
      const harmony = clampBandHarmony(band?.harmony)

      // Show cancellation check: Deterministic for harmony <= 1, probabilistic for low harmony (Chaos Tour Mechanic)
      const isLowHarmony = harmony < BALANCE_CONSTANTS.LOW_HARMONY_THRESHOLD
      const luckCheck =
        rng() < BALANCE_CONSTANTS.LOW_HARMONY_CANCELLATION_CHANCE
      const shouldCancel = harmony <= 1 || (isLowHarmony && luckCheck)

      if (shouldCancel) {
        addToast(
          i18n.t('ui:arrival.showCancelled', {
            defaultValue:
              'Show cancelled! The band refused to go on stage due to low harmony.'
          }),
          'error'
        )

        // Apply fame penalty directly (double the standard bad gig loss)
        if (player && updatePlayer) {
          const currentFame = player.fame || 0
          const loss = BALANCE_CONSTANTS.FAME_LOSS_BAD_GIG * 2
          const newFame = clampPlayerFame(currentFame - loss)
          updatePlayer({
            fame: newFame,
            fameLevel: calculateFameLevel(newFame)
          })
        }

        if (changeScene) changeScene(GAME_PHASES.OVERWORLD)
        return
      }

      logger.info('ArrivalLogic', 'Starting Gig at destination', {
        venue: node.venue.name
      })
      try {
        startGig(node.venue)
      } catch (error) {
        handleError(error, {
          addToast,
          fallbackMessage: i18n.t('ui:arrival.failedToStartGig', {
            defaultValue: 'Failed to start Gig.'
          })
        })
      }
      break
    }
  }
}

import * as Tone from 'tone'
import { logger } from '../logger'
import { audioState, resetGigState } from './state'

/**
 * Clears transport event by ID.
 * @param {number|null} id - Event ID.
 * @param {string} name - Event name for logging.
 */
export function clearTransportEvent(id: number | null, name: string): void {
  if (id == null) return
  try {
    Tone.getTransport().clear(id)
  } catch (err) {
    logger.warn('AudioEngine', `Failed to clear transport ${name} event`, err)
  }
}

/**
 * Stops and disconnects an audio source safely.
 * @param {AudioNode|null} source - The source node.
 * @param {string} name - Name for logging.
 */
export function stopAndDisconnectSource(
  source: AudioNode | null,
  name: string
): void {
  if (!source) return
  if (typeof (source as any).stop === 'function') {
    try {
      ;(source as any).stop()
    } catch (err) {
      logger.debug('AudioEngine', `${name} source stop failed`, err)
    }
  }
  if (typeof (source as any).disconnect === 'function') {
    try {
      ;(source as any).disconnect()
    } catch (err) {
      logger.debug('AudioEngine', `${name} source disconnect failed`, err)
    }
  }
}

/**
 * Stops Tone.js transport and clears common resources.
 */
export function stopTransportAndClear() {
  Tone.getTransport().stop()
  Tone.getTransport().position = 0
  if (audioState.loop) {
    audioState.loop.dispose()
    audioState.loop = null
  }
  if (audioState.part) {
    audioState.part.dispose()
    audioState.part = null
  }
  if (audioState.midiParts.length > 0) {
    audioState.midiParts.forEach(trackPart => trackPart.dispose())
    audioState.midiParts = []
  }
  Tone.getTransport().cancel()
}

/**
 * Cleans up gig playback resources and resets gig state.
 */
export function cleanupGigPlayback() {
  stopAndDisconnectSource(audioState.gigSource, 'Gig')
  resetGigState()
}

/**
 * Cleans up ambient playback resources.
 */
export function cleanupAmbientPlayback() {
  stopAndDisconnectSource(audioState.ambientSource, 'Ambient')
  audioState.ambientSource = null
}

/**
 * Cleans up transport event IDs.
 */
export function cleanupTransportEvents() {
  clearTransportEvent(audioState.transportEndEventId, 'end')
  audioState.transportEndEventId = null
  clearTransportEvent(audioState.transportStopEventId, 'stop')
  audioState.transportStopEventId = null
}

import * as Tone from 'tone'
import { logger } from '../logger'
import {
  canResumeAudioContextState,
  getPreferredAudioContextState,
  isClosedAudioContextState
} from '../audioContextState'
import { audioState } from './state'
import { setupAudio } from './setup'
import { disposeAudio } from './dispose'

/**
 * Returns the raw Web Audio context used by Tone.js.
 * @returns {AudioContext} The raw AudioContext.
 */
export const getRawAudioContext = (): AudioContext | any => {
  const toneContext = Tone.getContext()
  return toneContext?.rawContext ?? toneContext
}

/**
 * Returns the raw AudioContext time in seconds.
 * @returns {number} Current raw AudioContext time in seconds.
 */
export const getAudioContextTimeSec = (): number => {
  return getRawAudioContext().currentTime
}

/**
 * Converts a raw AudioContext start time into a Tone.js time reference.
 * @param {number} rawStartTimeSec - Raw AudioContext time in seconds.
 * @returns {number} Tone.js time in seconds.
 */
export const getToneStartTimeSec = (rawStartTimeSec: number): number => {
  const lookAhead = Tone.getContext()?.lookAhead ?? 0
  return rawStartTimeSec + lookAhead
}

/**
 * Ensures the AudioContext is running and initialized.
 * @returns {Promise<boolean>} True if the AudioContext is running.
 */
export async function ensureAudioContext(): Promise<boolean> {
  // Synchronous resume attempt to capture user gesture for Web Audio unlock (iOS/Safari).
  // Only attempt when audio is already set up to avoid resuming a stale context that
  // setupAudio() is about to replace.
  if (audioState.isSetup && Tone.context) {
    const earlyState = getPreferredAudioContextState({
      rawContextState: getRawAudioContext()?.state,
      toneContextState: Tone.context?.state
    })
    if (canResumeAudioContextState(earlyState)) {
      // On iOS Safari the 'interrupted' state requires the native AudioContext resume
      if (earlyState === 'interrupted') {
        try {
          const resumePromise = getRawAudioContext().resume()
          if (resumePromise && resumePromise.catch) {
            resumePromise.catch(() => {})
          }
        } catch (_e) {
          // Best-effort; full recovery follows below
        }
      } else {
        Tone.context.resume().catch(() => {})
      }
    }
  }

  if (!audioState.isSetup) {
    if (audioState.setupError) {
      audioState.setupError = null
    }
    try {
      await setupAudio()
    } catch (error) {
      logger.error('AudioEngine', 'setupAudio failed', error)
      return false
    }
  }

  const getAudioState = () => {
    let rawContextState = null
    let toneContextState = null

    try {
      rawContextState = getRawAudioContext()?.state
      toneContextState = Tone.context?.state
    } catch (error) {
      logger.debug('AudioEngine', 'Audio state read failed', error)
      return {
        state: getPreferredAudioContextState({
          rawContextState,
          toneContextState
        }),
        rawContextState,
        toneContextState
      }
    }

    return {
      state: getPreferredAudioContextState({
        rawContextState,
        toneContextState
      }),
      rawContextState,
      toneContextState
    }
  }

  const ensureRebuild = async (
    reasonState: string | null
  ): Promise<boolean> => {
    if (audioState.rebuildLock) {
      await audioState.rebuildLock
      return audioState.isSetup
    }

    let resolveRebuild: (() => void) | undefined
    audioState.rebuildLock = new Promise<void>(r => {
      resolveRebuild = r
    })

    try {
      logger.warn(
        'AudioEngine',
        `AudioContext state is ${reasonState}. Rebuilding audio graph.`
      )
      try {
        disposeAudio()
      } catch (error) {
        logger.debug(
          'AudioEngine',
          'Partial dispose before rebuild failed',
          error
        )
      }
      audioState.isSetup = false
      try {
        await setupAudio()
      } catch (error) {
        logger.error('AudioEngine', 'Rebuild setupAudio failed', error)
        audioState.isSetup = false
        return false
      }

      if (!audioState.isSetup) {
        logger.error(
          'AudioEngine',
          'Audio graph rebuild failed. Playback unavailable.'
        )
        return false
      }

      return true
    } finally {
      if (resolveRebuild) resolveRebuild()
      audioState.rebuildLock = null
    }
  }

  let audioStateCtx = getAudioState()
  if (isClosedAudioContextState(audioStateCtx.state)) {
    const rebuilt = await ensureRebuild(audioStateCtx.state)
    if (!rebuilt) return false
    audioStateCtx = getAudioState()
  }

  if (audioStateCtx.state === 'running') return true

  if (canResumeAudioContextState(audioStateCtx.state)) {
    try {
      await Tone.context.resume()
    } catch (error) {
      logger.warn('AudioEngine', 'Tone.context.resume() failed:', error)
    }
    audioStateCtx = getAudioState()
    if (audioStateCtx.state === 'running') return true
  }

  if (isClosedAudioContextState(audioStateCtx.state)) {
    const rebuiltAfterResume = await ensureRebuild(audioStateCtx.state)
    if (!rebuiltAfterResume) return false
    audioStateCtx = getAudioState()
  }

  return audioStateCtx.state === 'running'
}

import * as Tone from 'tone'
import * as ToneJsMidi from '@tonejs/midi'
import { logger } from '../logger'
import { audioState } from './state'
import { MIN_NOTE_DURATION, MAX_NOTE_DURATION } from './constants'
import { ensureAudioContext } from './context'
import { stopAudio, stopAudioInternal } from './playback'
import { midiUrlMap } from './assets'
import { calculateTimeFromTicks, preprocessTempoMap } from '../rhythmUtils'
import type { ProcessedTempoMapEntry } from '../../types/rhythm'
import {
  resolveAssetUrl,
  normalizeMidiPlaybackOptions,
  prepareTransportPlayback,
  getBaseAssetPath
} from './playbackUtils'
import { isPercussionTrack, normalizeMidiPitch, getNoteName } from './midiUtils'
import { playDrumNote } from './drumMappings'

type MaybeMidiModule = {
  Midi?: new (buf: ArrayBuffer) => unknown
  default?: { Midi?: new (buf: ArrayBuffer) => unknown }
}
const MidiParser =
  (ToneJsMidi as unknown as MaybeMidiModule).Midi ??
  (ToneJsMidi as unknown as MaybeMidiModule).default?.Midi ??
  null

// Local lightweight types for MIDI/song note shapes used in scheduling
type SongLikeNote = {
  t?: number
  p?: number
  v?: number
  lane?: string
  [key: string]: unknown
}

type ProcessedSongEvent = {
  time: number
  note: number
  noteName: string | null
  velocity: number
  lane: string
}

/**
 * Internal helper to trigger instrument notes.
 */
function triggerInstrumentNote(
  lane: string,
  midiPitch: number,
  time: number,
  velocity: number,
  noteName: string | null = null
): void {
  if (lane === 'drums') {
    playDrumNote(midiPitch, time, velocity)
  } else if (lane === 'bass') {
    if (audioState.bass) {
      const freq = noteName ?? getNoteName(midiPitch) ?? 'C3'
      audioState.bass.triggerAttackRelease(freq, '8n', time, velocity)
    }
  } else if (audioState.guitar) {
    const freq = noteName ?? getNoteName(midiPitch) ?? 'C4'
    audioState.guitar.triggerAttackRelease(freq, '16n', time, velocity)
  }
}

/**
 * Plays a specific note at a scheduled Tone.js time.
 * @param {number} midiPitch - The MIDI note number.
 * @param {string} lane - The lane ID ('guitar', 'bass', 'drums').
 * @param {number} whenSeconds - Tone.js time in seconds.
 * @param {number} [velocity=127] - The velocity (0-127).
 */
export function playNoteAtTime(
  midiPitch: number,
  lane: string,
  whenSeconds: number,
  velocity = 127
): void {
  if (!audioState.isSetup) return
  const now = Number.isFinite(whenSeconds) ? whenSeconds : Tone.now()
  const vel = Math.max(0, Math.min(1, velocity / 127))
  triggerInstrumentNote(lane, midiPitch, now, vel)
}

/**
 * Validates the song data and audio components readiness.
 */
function validateSongReady(song: unknown): boolean {
  const s = song as { notes?: unknown }
  if (!Array.isArray(s.notes)) {
    logger.error('AudioEngine', 'playSongFromData: song.notes is not an array')
    return false
  }

  if (!audioState.guitar || !audioState.bass || !audioState.drumKit) {
    logger.error(
      'AudioEngine',
      'playSongFromData: Audio components not initialized.'
    )
    return false
  }

  return true
}

/**
 * Processes song notes into schedulable events.
 */
function processSongEvents(
  song: { notes?: unknown },
  bpm: number,
  tpb: number,
  useTempoMap: boolean,
  activeTempoMap: ProcessedTempoMapEntry[]
): { events: ProcessedSongEvent[]; lastTime: number } | null {
  const events: ProcessedSongEvent[] = []
  let lastTime = 0

  const notes = Array.isArray(song.notes) ? (song.notes as SongLikeNote[]) : []

  for (let i = 0; i < notes.length; i++) {
    const n = notes[i]
    if (!n) continue

    if (
      typeof n.t !== 'number' ||
      !Number.isFinite(n.t) ||
      typeof n.p !== 'number' ||
      !Number.isFinite(n.p) ||
      typeof n.v !== 'number' ||
      !Number.isFinite(n.v)
    ) {
      continue
    }

    const time = useTempoMap
      ? calculateTimeFromTicks(n.t, tpb, activeTempoMap, 's')
      : (n.t / tpb) * (60 / bpm)

    const finalTime = Number.isFinite(time) ? time : -1

    if (finalTime >= 0) {
      const rawVelocity = Math.max(0, Math.min(127, n.v))

      if (finalTime > lastTime) {
        lastTime = finalTime
      }

      const noteName = n.lane !== 'drums' ? getNoteName(n.p) : null
      const lane = typeof n.lane === 'string' ? n.lane : 'guitar'

      events.push({
        time: finalTime,
        note: n.p,
        noteName,
        velocity: rawVelocity / 127,
        lane
      })
    }
  }

  if (events.length === 0) {
    logger.warn(
      'AudioEngine',
      'playSongFromData: No valid notes found to schedule'
    )
    return null
  }

  return { events, lastTime }
}

/**
 * Creates the Tone.Part for the song events.
 */
function createSongPart(events: ProcessedSongEvent[]) {
  const part = new Tone.Part((time: number, value: ProcessedSongEvent) => {
    try {
      if (!audioState.guitar || !audioState.bass || !audioState.drumKit) return

      const noteName =
        value.noteName === null
          ? null
          : (value.noteName ?? getNoteName(value.note))

      triggerInstrumentNote(
        value.lane,
        value.note,
        time,
        value.velocity,
        noteName
      )
    } catch (err) {
      logger.error('AudioEngine', 'Error in Song callback', err)
    }
  }, events).start(0)
  return part as unknown as Tone.Part<unknown>
}

/**
 * Schedules the song playback on the Transport.
 */
function scheduleSongPlayback(
  lastTime: number,
  delay: number,
  reqId: number,
  onEnded?: (() => void) | null
): void {
  const minLookahead = 0.1
  const startTime = Tone.now() + Math.max(minLookahead, delay)

  if (onEnded) {
    const duration = lastTime + Tone.Time('4n').toSeconds()

    Tone.getTransport().scheduleOnce(() => {
      if (reqId !== audioState.playRequestId) return
      onEnded()
    }, duration)
  }

  Tone.getTransport().start(startTime)
}

/**
 * Plays a song using predefined note data.
 * @param {object} song - The song object containing `notes` and `bpm`.
 * @param {number} [delay=0] - Delay in seconds before starting.
 */
export async function playSongFromData(
  song: unknown,
  delay = 0,
  options: unknown = {}
): Promise<boolean> {
  const { success, reqId, normalizedOptions } =
    await prepareTransportPlayback(options)
  if (!success) return false
  const { onEnded } = normalizedOptions

  // Narrow the incoming `song` shape safely from `unknown`.
  const sObj =
    song && typeof song === 'object' ? (song as Record<string, unknown>) : {}
  const toFiniteNumber = (v: unknown, fallback: number): number => {
    if (typeof v === 'number' && Number.isFinite(v)) return v
    if (typeof v === 'string' && v.trim() !== '' && !Number.isNaN(Number(v)))
      return Number(v)
    return fallback
  }

  const bpm = Math.max(1, toFiniteNumber(sObj.bpm, 120))
  const tpb = Math.max(1, toFiniteNumber(sObj.tpb, 480))

  if (!validateSongReady(song)) return false

  const useTempoMap =
    Array.isArray(sObj.tempoMap) && (sObj.tempoMap as unknown[]).length > 0
  let activeTempoMap: ProcessedTempoMapEntry[] = []
  if (useTempoMap && Array.isArray(sObj.tempoMap)) {
    const rawTempo = sObj.tempoMap as unknown[]
    const sanitized: { tick: number; usPerBeat: number }[] = []
    for (let i = 0; i < rawTempo.length; i++) {
      const e = rawTempo[i]
      if (
        typeof e === 'object' &&
        e !== null &&
        'tick' in e &&
        'usPerBeat' in e
      ) {
        const obj = e as Record<string, unknown>
        const tickVal = obj['tick']
        const usPerBeatVal = obj['usPerBeat']
        if (typeof tickVal === 'number' && typeof usPerBeatVal === 'number') {
          sanitized.push({ tick: tickVal, usPerBeat: usPerBeatVal })
        }
      }
    }
    activeTempoMap = preprocessTempoMap(sanitized, tpb)
  }

  const validDelay = Number.isFinite(delay) ? Math.max(0, delay) : 0

  const processingResult = processSongEvents(
    {
      notes: Array.isArray(sObj.notes)
        ? (sObj.notes as SongLikeNote[])
        : undefined
    },
    bpm,
    tpb,
    useTempoMap,
    activeTempoMap
  )
  if (!processingResult) return false

  Tone.getTransport().bpm.value = bpm
  const { events, lastTime } = processingResult

  audioState.part = createSongPart(events)

  scheduleSongPlayback(lastTime, validDelay, reqId, onEnded)
  return true
}

/**
 * Handles the initial setup for MIDI playback, including request ID generation.
 * @param {string} filename - The filename of the MIDI.
 * @param {number} offset - Start offset in seconds.
 * @param {boolean} loop - Whether to loop the playback.
 * @param {number|null} ownedRequestId - Internal request ownership override.
 * @returns {number} The new request ID.
 */
function initializePlaybackRequest(
  filename: string,
  offset: number,
  loop: boolean,
  ownedRequestId: number | null
): number {
  logger.debug(
    'AudioEngine',
    `Request playMidiFile: ${filename}, offset=${offset}, loop=${loop}`
  )
  const reqId =
    typeof ownedRequestId === 'number' &&
    Number.isInteger(ownedRequestId) &&
    ownedRequestId > 0
      ? ownedRequestId
      : ++audioState.playRequestId
  logger.debug('AudioEngine', `New playRequestId: ${reqId}`)
  return reqId
}

/**
 * Resolves the URL for a MIDI file.
 * @param {string} filename - The filename of the MIDI.
 * @returns {string|null} The resolved URL or null if not found.
 */
function resolveMidiUrl(filename: string): string | null {
  const { publicBasePath } = getBaseAssetPath()
  const { url, source } = resolveAssetUrl(filename, midiUrlMap, publicBasePath)
  logger.debug(
    'AudioEngine',
    `Resolved MIDI URL for ${filename}: ${url} (source=${source ?? 'none'})`
  )

  if (!url) {
    logger.error('AudioEngine', `MIDI file not found in assets: ${filename}`)
    return null
  }
  return url
}

/**
 * Fetches the MIDI file as an ArrayBuffer.
 * @param {string} url - The URL of the MIDI file.
 * @param {number} reqId - The request ID to validate against.
 * @param {string} filename - The filename for logging.
 * @returns {Promise<ArrayBuffer|null>} The MIDI data or null on failure.
 */
async function fetchMidiArrayBuffer(
  url: string,
  reqId: number,
  filename: string
): Promise<ArrayBuffer | null> {
  try {
    const controller = new AbortController()
    const timeoutId = setTimeout(
      () => controller.abort(),
      10000 // 10s timeout for MIDI fetch
    )
    let arrayBuffer = null
    try {
      const response = await fetch(url, { signal: controller.signal })
      if (reqId !== audioState.playRequestId) return null
      if (!response.ok) throw new Error(`Failed to load MIDI: ${url}`)
      arrayBuffer = await response.arrayBuffer()
    } finally {
      clearTimeout(timeoutId)
    }
    if (reqId !== audioState.playRequestId) return null
    return arrayBuffer
  } catch (err) {
    if (err instanceof Error && (err as Error).name === 'AbortError') {
      logger.warn('AudioEngine', `MIDI fetch timed out for "${filename}"`)
    } else {
      logger.error('AudioEngine', 'Error playing MIDI:', err)
    }
    return null
  }
}

/**
 * Parses the MIDI ArrayBuffer.
 * @param {ArrayBuffer} arrayBuffer - The MIDI data.
 * @returns {object|null} The parsed MIDI object or null on failure.
 */
function parseMidiData(arrayBuffer: ArrayBuffer): unknown | null {
  if (!MidiParser) {
    logger.error(
      'AudioEngine',
      'MidiParser failed to load from @tonejs/midi. This disables all MIDI playback. Try: npm install @tonejs/midi --force and restart the dev server. If the issue persists, check bundler ESM/CJS interop configuration.'
    )
    return null
  }

  const Ctor = MidiParser as unknown as { new (buf: ArrayBuffer): unknown }
  const midiObj = new Ctor(arrayBuffer)
  const midiRec = midiObj as Record<string, unknown>
  const duration = typeof midiRec.duration === 'number' ? midiRec.duration : 0
  logger.debug('AudioEngine', `MIDI loaded. Duration: ${duration}s`)

  if (duration <= 0) {
    logger.warn(
      'AudioEngine',
      `MIDI duration is ${duration}s. Skipping playback.`
    )
    return null
  }
  return midiObj
}

/**
 * Creates Tone.Parts for each track in the MIDI file.
 * @param {object} midi - The parsed MIDI object.
 * @param {boolean} useCleanPlayback - If true, bypass FX for MIDI playback.
 * @returns {Array} An array of created Tone.Part objects.
 */
function createMidiParts(
  midi: any,
  useCleanPlayback: boolean
): Tone.Part<unknown>[] {
  const leadSynth = useCleanPlayback ? audioState.midiLead : audioState.guitar
  const bassSynth = useCleanPlayback ? audioState.midiBass : audioState.bass
  const drumSet = useCleanPlayback ? audioState.midiDrumKit : audioState.drumKit

  type MidiEvent = {
    time: number
    midiPitch: number
    duration?: number | string | null
    velocity?: number | null
    percussionTrack: boolean
    frequencyNote?: string | null
  }

  const nextMidiParts: Tone.Part<unknown>[] = []
  const tracks = Array.isArray(midi?.tracks) ? midi.tracks : []
  for (const track of tracks as unknown[]) {
    const notes = Array.isArray((track as any)?.notes)
      ? (track as any).notes
      : []
    const percussionTrack = isPercussionTrack(track)

    const eventsWithFrequencies: MidiEvent[] = []

    for (const note of notes) {
      if (!Number.isFinite((note as any)?.time) || (note as any).time < 0)
        continue
      const midiPitch = normalizeMidiPitch(note)
      if (midiPitch == null) continue

      const evt: MidiEvent = {
        time: (note as any).time,
        midiPitch,
        duration: (note as any).duration,
        velocity: (note as any).velocity,
        percussionTrack
      }

      if (!percussionTrack) {
        evt.frequencyNote = getNoteName(midiPitch)
      }

      eventsWithFrequencies.push(evt)
    }

    if (eventsWithFrequencies.length === 0) continue

    const trackPart = new Tone.Part((time: number, value: MidiEvent) => {
      try {
        if (!leadSynth || !bassSynth || !drumSet) return

        const midiPitch = value.midiPitch

        const duration = Math.min(
          MAX_NOTE_DURATION,
          Math.max(
            MIN_NOTE_DURATION,
            Number.isFinite(value.duration as number)
              ? (value.duration as number)
              : MIN_NOTE_DURATION
          )
        )

        const velocity = Math.max(
          0,
          Math.min(
            1,
            Number.isFinite(value.velocity as number)
              ? (value.velocity as number)
              : 1
          )
        )

        if (value.percussionTrack) {
          playDrumNote(midiPitch, time, velocity, drumSet)
          return
        }

        const freq = value.frequencyNote ?? getNoteName(midiPitch) ?? 'C4'

        if (midiPitch < 45) {
          bassSynth.triggerAttackRelease(freq, duration, time, velocity)
        } else {
          leadSynth.triggerAttackRelease(freq, duration, time, velocity)
        }
      } catch (err) {
        logger.error('AudioEngine', 'Error in MIDI callback', err)
      }
    }, eventsWithFrequencies) as unknown as Tone.Part<unknown>

    trackPart.start(0)
    nextMidiParts.push(trackPart)
  }
  return nextMidiParts
}

/**
 * Configures the Transport and schedules playback.
 * @param {object} midi - The parsed MIDI object.
 * @param {object} params - Parameters for scheduling.
 */
function scheduleMidiTransport(midi: any, params: any): void {
  const {
    reqId,
    filename,
    offset,
    loop,
    delay,
    onEnded,
    stopAfterSeconds,
    startTimeSec
  } = params

  if (midi.header.tempos.length > 0) {
    Tone.getTransport().bpm.value = midi.header.tempos[0].bpm
  }

  const validDelay = Number.isFinite(delay) ? Math.max(0, delay) : 0
  let requestedOffset = Number.isFinite(offset) ? Math.max(0, offset) : 0
  const duration = Number.isFinite(midi.duration) ? midi.duration : 0

  // Reset offset when it is at or beyond duration to ensure sound plays.
  if (duration > 0 && requestedOffset >= duration) {
    logger.warn(
      'AudioEngine',
      `Offset ${requestedOffset}s exceeds duration ${duration}s. Resetting to 0.`
    )
    requestedOffset = 0
  }

  logger.debug(
    'AudioEngine',
    `Starting Transport. Delay=${validDelay}, Offset=${requestedOffset}`
  )

  if (loop) {
    Tone.getTransport().loop = true
    Tone.getTransport().loopEnd = midi.duration
    // Loop from excerpt start, so intros don't restart on every loop
    Tone.getTransport().loopStart = requestedOffset
  } else {
    Tone.getTransport().loop = false
  }

  if (!loop && onEnded && duration > 0) {
    audioState.transportEndEventId = Tone.getTransport().scheduleOnce(() => {
      if (reqId !== audioState.playRequestId) return
      onEnded({
        filename,
        duration,
        offsetSeconds: requestedOffset
      })
    }, duration)
  }

  if (!loop && Number.isFinite(stopAfterSeconds) && stopAfterSeconds > 0) {
    const stopTime = requestedOffset + stopAfterSeconds
    audioState.transportStopEventId = Tone.getTransport().scheduleOnce(() => {
      if (reqId !== audioState.playRequestId) return
      stopAudio()
    }, stopTime)
  }

  // Schedule Transport.start in advance to prevent pops/crackles
  // Add minimum 100ms lookahead for reliable scheduling
  const minLookahead = 0.1
  const transportStartTime = Number.isFinite(startTimeSec)
    ? startTimeSec
    : Tone.now() + Math.max(minLookahead, validDelay)

  Tone.getTransport().start(transportStartTime, requestedOffset)
}

/**
 * Plays a MIDI file from a URL.
 * @param {object} params - Parameters for playback.
 * @param {string} params.filename - The filename of the MIDI (key in url map).
 * @param {number} [params.offset=0] - Start offset in seconds.
 * @param {boolean} [params.loop=false] - Whether to loop the playback.
 * @param {number} [params.delay=0] - Delay in seconds before starting playback.
 * @param {object} [params.options] - Playback options.
 * @param {boolean} [params.options.useCleanPlayback=true] - If true, bypass FX for MIDI playback.
 * @param {Function} [params.options.onEnded] - Callback invoked after playback ends.
 * @param {number} [params.options.stopAfterSeconds] - Optional playback duration limit in seconds.
 * @param {number} [params.options.startTimeSec] - Absolute Tone.js time to start playback.
 * @param {number|null} [params.ownedRequestId=null] - Internal request ownership override.
 */
export async function playMidiFileInternal(params: any = {}): Promise<boolean> {
  const {
    filename,
    offset = 0,
    loop = false,
    delay = 0,
    options = {},
    ownedRequestId = null
  } = params

  const { onEnded, useCleanPlayback, stopAfterSeconds, startTimeSec } =
    normalizeMidiPlaybackOptions(options)

  const reqId = initializePlaybackRequest(
    filename,
    offset,
    loop,
    ownedRequestId
  )

  const unlocked = await ensureAudioContext()
  if (!unlocked) {
    logger.warn('AudioEngine', 'Cannot play MIDI: AudioContext is locked')
    return false
  }

  if (reqId !== audioState.playRequestId) {
    logger.debug(
      'AudioEngine',
      `Request cancelled during ensureAudioContext (reqId: ${reqId} vs ${audioState.playRequestId})`
    )
    return false
  }

  stopAudioInternal()
  Tone.getTransport().cancel()

  const url = resolveMidiUrl(filename)
  if (!url) return false

  const arrayBuffer = await fetchMidiArrayBuffer(url, reqId, filename)
  if (!arrayBuffer) return false
  if (reqId !== audioState.playRequestId) return false

  const midi = parseMidiData(arrayBuffer)
  if (!midi) return false
  if (reqId !== audioState.playRequestId) return false

  const parts = createMidiParts(midi, useCleanPlayback)
  audioState.midiParts = parts

  scheduleMidiTransport(midi, {
    reqId,
    filename,
    offset,
    loop,
    delay,
    onEnded,
    stopAfterSeconds,
    startTimeSec
  })

  return true
}

/**
 * Plays a MIDI file from a URL.
 * @param {string} filename - The filename of the MIDI (key in url map).
 * @param {number} [offset=0] - Start offset in seconds.
 * @param {boolean} [loop=false] - Whether to loop the playback.
 * @param {number} [delay=0] - Delay in seconds before starting playback.
 * @param {object} [options] - Playback options.
 * @param {boolean} [options.useCleanPlayback=true] - If true, bypass FX for MIDI playback.
 * @param {Function} [options.onEnded] - Callback invoked after playback ends.
 * @param {number} [options.stopAfterSeconds] - Optional playback duration limit in seconds.
 * @param {number} [options.startTimeSec] - Absolute Tone.js time to start playback.
 */
export async function playMidiFile(
  filename: string,
  offset = 0,
  loop = false,
  delay = 0,
  options: any = {}
): Promise<boolean> {
  return playMidiFileInternal({ filename, offset, loop, delay, options })
}

import * as Tone from 'tone'
import { logger } from '../logger'
import { audioState } from './state'
import { ensureAudioContext } from './context'
import { getRawAudioContext, getAudioContextTimeSec } from './context'
import { loadAudioBuffer } from './assets'
import { createAndConnectBufferSource } from './sharedBufferUtils'
import {
  stopTransportAndClear,
  cleanupGigPlayback,
  cleanupAmbientPlayback,
  cleanupTransportEvents
} from './cleanupUtils'

/**
 * Plays a sound effect by type.
 * @param {string} type - The type of SFX ('hit', 'miss', 'menu', 'travel', 'cash').
 */
export function playSFX(type: string): void {
  if (!audioState.isSetup || !audioState.sfxSynth) return

  const now = Tone.now()
  switch (type) {
    case 'hit':
      // High pitch success ping
      audioState.sfxSynth.triggerAttackRelease('A5', '16n', now)
      break
    case 'miss':
      // Low discordant buzz
      audioState.sfxSynth.triggerAttackRelease('D2', '8n', now)
      break
    case 'menu':
      // Gentle blip
      audioState.sfxSynth.triggerAttackRelease('C5', '32n', now, 0.3)
      break
    case 'travel':
      // Engine-like rumble using drum kick if available, or low synth
      if (audioState.drumKit && audioState.drumKit.kick) {
        audioState.drumKit.kick.triggerAttackRelease('C1', '8n', now, 0.5)
      } else {
        audioState.sfxSynth.triggerAttackRelease('G1', '8n', now, 0.5)
      }
      break
    case 'cash':
      // Bright chime/coin sound
      audioState.sfxSynth.triggerAttackRelease('B5', '16n', now, 0.4)
      audioState.sfxSynth.triggerAttackRelease('E6', '16n', now + 0.05, 0.4)
      break
    case 'crash':
      // Low noise burst
      audioState.sfxSynth.triggerAttackRelease('C1', '8n', now, 1.0)
      audioState.sfxSynth.triggerAttackRelease('F1', '8n', now + 0.02, 0.8)
      break
    case 'honk':
      // Car horn
      audioState.sfxSynth.triggerAttackRelease('F#4', '8n', now, 0.6)
      audioState.sfxSynth.triggerAttackRelease('A4', '8n', now, 0.6)
      break
    case 'pickup':
      // Quick upward blip
      audioState.sfxSynth.triggerAttackRelease('C5', '32n', now, 0.5)
      audioState.sfxSynth.triggerAttackRelease('E5', '32n', now + 0.05, 0.5)
      break
    case 'deliver':
      // Heavy success thud
      audioState.sfxSynth.triggerAttackRelease('C2', '4n', now, 0.8)
      audioState.sfxSynth.triggerAttackRelease('G2', '4n', now, 0.6)
      break
    default:
      logger.warn('AudioEngine', `Unknown SFX type: ${type}`)
      break
  }
}

/**
 * Sets the SFX volume.
 * @param {number} vol - Volume between 0 and 1.
 * @returns {boolean} True when applied to an existing gain node.
 */
export function setSFXVolume(vol: number): boolean {
  if (!audioState.sfxGain) return false
  // Convert 0-1 linear to decibels (approximate or use ramp)
  // Tone.Gain accepts linear values if units are default, but volume is typically db.
  // However, Tone.Gain.gain is linear amplitude.
  audioState.sfxGain.gain.rampTo(Math.max(0, Math.min(1, vol)), 0.1)
  return true
}

/**
 * Sets the music volume using the dedicated music bus.
 * @param {number} vol - Volume between 0 and 1.
 * @returns {boolean} True when applied to an existing gain node.
 */
export function setMusicVolume(vol: number): boolean {
  if (!audioState.musicGain) return false
  const next = Math.max(0, Math.min(1, vol))
  audioState.musicGain.gain.rampTo(next, 0.1)
  return true
}

/**
 * Calculates gig time in milliseconds based on context time.
 * @param {object} params - Calculation inputs.
 * @param {number} params.contextTimeSec - Raw audio context time in seconds.
 * @param {number|null} params.startCtxTimeSec - Context time when gig playback started.
 * @param {number} params.offsetMs - Offset in milliseconds to apply.
 * @returns {number} Calculated gig time in milliseconds.
 */
export const calculateGigTimeMs = ({
  contextTimeSec,
  startCtxTimeSec,
  offsetMs
}: {
  contextTimeSec: number
  startCtxTimeSec: number | null
  offsetMs?: number
}): number => {
  const safeOffset = Number.isFinite(offsetMs) ? (offsetMs as number) : 0
  if (
    !Number.isFinite(contextTimeSec) ||
    typeof startCtxTimeSec !== 'number' ||
    !Number.isFinite(startCtxTimeSec)
  ) {
    return safeOffset
  }
  return (contextTimeSec - startCtxTimeSec) * 1000 + safeOffset
}

/**
 * Returns the current gig time in ms.
 * This uses the raw Web Audio context for sample-accurate sync with buffers.
 * @returns {number} Current gig time in ms.
 */
export function getGigTimeMs() {
  const rawContext = getRawAudioContext()
  return calculateGigTimeMs({
    contextTimeSec: rawContext.currentTime,
    startCtxTimeSec: audioState.gigStartCtxTime,
    offsetMs: audioState.gigSeekOffsetMs
  })
}

/**
 * Handles cleanup when a gig buffer source ends naturally.
 * @param {AudioBufferSourceNode} source - The ended source node.
 * @returns {void}
 */
const handleGigSourceEnded = (source: any): void => {
  if (audioState.gigSource !== source || audioState.gigIsPaused) return
  if (audioState.gigOnEnded) {
    audioState.gigOnEnded({
      filename: audioState.gigFilename,
      durationMs: audioState.gigDurationMs,
      offsetMs: audioState.gigBaseOffsetMs
    })
  }
  audioState.gigSeekOffsetMs = getGigTimeMs()
  audioState.gigStartCtxTime = null
  audioState.gigSource = null
}

const createGigBufferSource = ({
  buffer,
  onEnded
}: {
  buffer: any
  onEnded?: any
}): any => {
  return createAndConnectBufferSource(buffer, onEnded)
}

/**
 * Calculates buffer playback offsets and safe duration for gig playback.
 * @param {object} params - Playback window params.
 * @param {number} params.bufferDurationSec - Audio buffer duration in seconds.
 * @param {number} params.baseOffsetMs - Base offset in milliseconds.
 * @param {number} params.seekOffsetMs - Seek offset in milliseconds.
 * @param {number|null} params.durationMs - Requested playback duration in milliseconds.
 * @returns {{offsetSeconds: number, requestedOffsetSeconds: number, safeDurationSeconds: number|null, nextBaseOffsetMs: number, nextSeekOffsetMs: number, didResetOffsets: boolean}} Playback window.
 */
export const calculateGigPlaybackWindow = ({
  bufferDurationSec,
  baseOffsetMs,
  seekOffsetMs,
  durationMs
}: {
  bufferDurationSec: number
  baseOffsetMs: number
  seekOffsetMs: number
  durationMs: number | null
}) => {
  const safeBaseOffsetMs = Number.isFinite(baseOffsetMs)
    ? Math.max(0, baseOffsetMs)
    : 0
  const safeSeekOffsetMs = Number.isFinite(seekOffsetMs)
    ? Math.max(0, seekOffsetMs)
    : 0
  const safeBufferDurationSec = Number.isFinite(bufferDurationSec)
    ? Math.max(0, bufferDurationSec)
    : 0
  const safeDurationMs =
    typeof durationMs === 'number' && Number.isFinite(durationMs)
      ? Math.max(0, durationMs)
      : null
  let nextBaseOffsetMs = safeBaseOffsetMs
  let nextSeekOffsetMs = safeSeekOffsetMs
  const requestedOffsetSeconds = (safeBaseOffsetMs + safeSeekOffsetMs) / 1000
  let offsetSeconds = requestedOffsetSeconds
  let didResetOffsets = false

  if (safeBufferDurationSec > 0 && offsetSeconds >= safeBufferDurationSec) {
    offsetSeconds = 0
    nextBaseOffsetMs = 0
    nextSeekOffsetMs = 0
    didResetOffsets = true
  }

  const durationSeconds = safeDurationMs != null ? safeDurationMs / 1000 : null
  const safeDurationSeconds =
    durationSeconds != null && safeBufferDurationSec > 0
      ? Math.min(
          durationSeconds,
          Math.max(0, safeBufferDurationSec - offsetSeconds)
        )
      : durationSeconds

  return {
    offsetSeconds,
    requestedOffsetSeconds,
    safeDurationSeconds,
    nextBaseOffsetMs,
    nextSeekOffsetMs,
    didResetOffsets
  }
}

/**
 * Stops gig playback and clears the gig clock state.
 * @returns {void}
 */
export function stopGigPlayback() {
  if (audioState.gigSource) {
    logger.debug(
      'AudioEngine',
      `Stopping gig playback: "${audioState.gigFilename}" at ${getGigTimeMs().toFixed(0)}ms`
    )
  }
  cleanupGigPlayback()
}

/**
 * Starts gig playback using Web Audio buffer playback.
 * @param {object} params - Playback params.
 * @param {string} params.filename - Audio filename to play.
 * @param {number} [params.bufferOffsetMs=0] - Offset into the buffer in ms.
 * @param {number} [params.delayMs=0] - Delay before starting playback in ms.
 * @param {number} [params.durationMs=null] - Optional playback duration in ms.
 * @param {Function} [params.onEnded] - Callback invoked after playback ends.
 * @returns {Promise<boolean>} True when playback starts.
 */
export async function startGigPlayback({
  filename,
  bufferOffsetMs = 0,
  delayMs = 0,
  durationMs = null,
  onEnded = null
}: {
  filename: string
  bufferOffsetMs?: number
  delayMs?: number
  durationMs?: number | null
  onEnded?: ((args: any) => void) | null
}): Promise<boolean> {
  const unlocked = await ensureAudioContext()
  if (!unlocked) return false

  stopGigPlayback()

  const buffer = await loadAudioBuffer(filename)
  if (!buffer) return false

  const rawContext = getRawAudioContext()
  const source = createGigBufferSource({
    buffer,
    onEnded: handleGigSourceEnded
  })
  if (!source) return false

  audioState.gigBuffer = buffer
  audioState.gigFilename = filename
  audioState.gigBaseOffsetMs = Math.max(0, bufferOffsetMs)
  audioState.gigSeekOffsetMs = 0
  audioState.gigDurationMs =
    typeof durationMs === 'number' && Number.isFinite(durationMs)
      ? Math.max(0, durationMs)
      : null
  audioState.gigOnEnded = typeof onEnded === 'function' ? onEnded : null
  audioState.gigIsPaused = false

  const startAt = rawContext.currentTime + Math.max(0, delayMs) / 1000
  audioState.gigStartCtxTime = startAt

  const {
    offsetSeconds,
    requestedOffsetSeconds,
    safeDurationSeconds,
    nextBaseOffsetMs,
    nextSeekOffsetMs,
    didResetOffsets
  } = calculateGigPlaybackWindow({
    bufferDurationSec: buffer.duration,
    baseOffsetMs: audioState.gigBaseOffsetMs,
    seekOffsetMs: audioState.gigSeekOffsetMs,
    durationMs: audioState.gigDurationMs
  })

  if (didResetOffsets) {
    logger.warn(
      'AudioEngine',
      `Audio offset ${requestedOffsetSeconds}s exceeds buffer duration ${buffer.duration}s. Resetting to 0.`
    )
    audioState.gigBaseOffsetMs = nextBaseOffsetMs
    audioState.gigSeekOffsetMs = nextSeekOffsetMs
  }

  audioState.gigSource = source
  if (safeDurationSeconds === 0) {
    logger.debug(
      'AudioEngine',
      `Gig playback: zero duration after clamping, firing onEnded immediately.`
    )
    audioState.gigStartCtxTime = null
    handleGigSourceEnded(source)
    return true
  }

  try {
    Tone.getTransport().start(startAt, offsetSeconds)
  } catch (error) {
    logger.warn('AudioEngine', 'Failed to start Tone.Transport', error)
  }

  try {
    if (safeDurationSeconds != null && safeDurationSeconds > 0) {
      source.start(startAt, offsetSeconds, safeDurationSeconds)
    } else {
      source.start(startAt, offsetSeconds)
    }
  } catch (error) {
    logger.warn(
      'AudioEngine',
      'source.start() failed — context may be suspended',
      error
    )
    try {
      Tone.getTransport().stop()
    } catch {
      /* ignore */
    }
    cleanupGigPlayback()
    return false
  }
  logger.info(
    'AudioEngine',
    `Gig playback started: "${filename}" offset=${offsetSeconds.toFixed(2)}s duration=${safeDurationSeconds != null ? safeDurationSeconds.toFixed(2) + 's' : 'full'}`
  )
  return true
}

/**
 * Starts the gig clock without buffer playback (e.g. for MIDI fallback).
 * @param {object} params - Clock params.
 * @param {number} [params.delayMs=0] - Delay before starting the clock in ms.
 * @param {number} [params.offsetMs=0] - Starting offset for the gig clock.
 * @param {number|null} [params.startTimeSec=null] - Absolute Tone.js time to start the gig clock.
 * @returns {void}
 */
export function startGigClock({
  delayMs = 0,
  offsetMs = 0,
  startTimeSec = null
}: {
  delayMs?: number
  offsetMs?: number
  startTimeSec?: number | null
} = {}): void {
  const startTime = Number.isFinite(startTimeSec)
    ? startTimeSec
    : getAudioContextTimeSec() + Math.max(0, delayMs) / 1000
  audioState.gigStartCtxTime = startTime
  audioState.gigSeekOffsetMs = Math.max(0, offsetMs)
  audioState.gigIsPaused = false
  audioState.gigBuffer = null
  audioState.gigFilename = null
  audioState.gigDurationMs = null
  audioState.gigBaseOffsetMs = 0
  audioState.gigOnEnded = null
  if (audioState.gigSource) {
    try {
      audioState.gigSource.stop()
    } catch (error) {
      logger.warn('AudioEngine', 'Failed to reset gig source', error)
    }
    audioState.gigSource = null
  }
}

/**
 * Pauses gig playback and preserves the current offset.
 * @returns {void}
 */
export function pauseGigPlayback(): void {
  if (audioState.gigIsPaused) return
  if (!audioState.gigSource && audioState.gigStartCtxTime == null) return
  logger.debug(
    'AudioEngine',
    `Pausing gig playback at ${getGigTimeMs().toFixed(0)}ms`
  )
  audioState.gigSeekOffsetMs = getGigTimeMs()
  audioState.gigIsPaused = true
  audioState.gigStartCtxTime = null
  if (audioState.gigSource) {
    try {
      audioState.gigSource.stop()
    } catch (error) {
      logger.warn('AudioEngine', 'Failed to pause gig playback', error)
    }
    try {
      audioState.gigSource.disconnect()
    } catch {
      // Source may already be disconnected after stop
    }
    audioState.gigSource = null
  }
}

/**
 * Resumes gig playback from the stored offset.
 * @returns {boolean} True on success or no-op, false on source.start() failure.
 */
export function resumeGigPlayback(): boolean {
  if (!audioState.gigIsPaused) return true
  logger.debug(
    'AudioEngine',
    `Resuming gig playback from ${audioState.gigSeekOffsetMs.toFixed(0)}ms`
  )
  if (!audioState.gigBuffer) {
    audioState.gigStartCtxTime = getRawAudioContext().currentTime
    audioState.gigIsPaused = false
    return true
  }
  const source = createGigBufferSource({
    buffer: audioState.gigBuffer,
    onEnded: handleGigSourceEnded
  })
  if (!source) return false

  const startAt = getRawAudioContext().currentTime
  audioState.gigStartCtxTime = startAt
  audioState.gigIsPaused = false

  const remainingDurationMs =
    audioState.gigDurationMs != null
      ? Math.max(0, audioState.gigDurationMs - audioState.gigSeekOffsetMs)
      : null
  const {
    offsetSeconds,
    requestedOffsetSeconds,
    safeDurationSeconds,
    nextBaseOffsetMs,
    nextSeekOffsetMs,
    didResetOffsets
  } = calculateGigPlaybackWindow({
    bufferDurationSec: audioState.gigBuffer.duration,
    baseOffsetMs: audioState.gigBaseOffsetMs,
    seekOffsetMs: audioState.gigSeekOffsetMs,
    durationMs: remainingDurationMs
  })

  if (didResetOffsets) {
    logger.warn(
      'AudioEngine',
      `Audio offset ${requestedOffsetSeconds}s exceeds buffer duration ${audioState.gigBuffer.duration}s. Resetting to 0.`
    )
    audioState.gigBaseOffsetMs = nextBaseOffsetMs
    audioState.gigSeekOffsetMs = nextSeekOffsetMs
  }

  audioState.gigSource = source
  if (safeDurationSeconds === 0) {
    audioState.gigStartCtxTime = null
    handleGigSourceEnded(source)
    return true
  }
  try {
    if (safeDurationSeconds != null && safeDurationSeconds > 0) {
      source.start(startAt, offsetSeconds, safeDurationSeconds)
    } else {
      source.start(startAt, offsetSeconds)
    }
  } catch (error) {
    logger.warn(
      'AudioEngine',
      'source.start() failed on resume — context may be suspended',
      error
    )
    // Null the source that failed to start, but preserve buffer and seek offset for retry
    try {
      audioState.gigSource?.stop?.()
    } catch {
      /* already stopped */
    }
    try {
      audioState.gigSource?.disconnect?.()
    } catch {
      /* already disconnected */
    }
    audioState.gigSource = null
    audioState.gigStartCtxTime = null
    audioState.gigIsPaused = true // revert to paused so caller can retry
    try {
      Tone.getTransport().pause()
    } catch {
      /* ignore */
    }
    return false
  }
  return true
}

/**
 * Internal function to stop audio without invalidating pending requests.
 * Used by playback functions to clear previous state.
 */
export function stopAudioInternal(): void {
  stopTransportAndClear()
  cleanupTransportEvents()
}

/**
 * Stops ambient OGG playback and clears ambient state.
 * @returns {void}
 */
export function stopAmbientPlayback(): void {
  if (audioState.ambientSource) {
    logger.debug('AudioEngine', 'Stopping ambient OGG playback.')
  }
  cleanupAmbientPlayback()
}

/**
 * Stops the audio transport and disposes of the current loop.
 * Also invalidates any pending playback requests.
 */
export function stopAudio(): void {
  audioState.playRequestId++
  logger.debug(
    'AudioEngine',
    `stopAudio called. Invalidating reqs. New reqId: ${audioState.playRequestId}`
  )
  stopAudioInternal()
  stopGigPlayback()
  stopAmbientPlayback()
}

/**
 * Pauses the audio transport.
 * @returns {Promise<void>} Resolves when pause is complete.
 */
export async function pauseAudio(): Promise<void> {
  try {
    if (Tone.getTransport().state === 'started') {
      const p = Tone.getTransport().pause()
      const maybeThenable = p as unknown as { then?: unknown }
      if (maybeThenable && typeof maybeThenable.then === 'function') {
        await (p as unknown as Promise<unknown>)
      }
    }
  } catch (err) {
    logger.warn('AudioEngine', 'Failed to pause audio transport', err)
  }
  try {
    pauseGigPlayback()
  } catch (err) {
    logger.warn('AudioEngine', 'Failed to pause gig playback', err)
  }
}

/**
 * Resumes the audio transport.
 * @returns {Promise<boolean>} Resolves to the boolean result of resumeGigPlayback() when resume is complete.
 */
export async function resumeAudio(): Promise<boolean> {
  try {
    if (Tone.getTransport().state === 'paused') {
      const p = Tone.getTransport().start()
      const maybeThenable = p as unknown as { then?: unknown }
      if (maybeThenable && typeof maybeThenable.then === 'function') {
        await (p as unknown as Promise<unknown>)
      }
    }
  } catch (err) {
    logger.warn('AudioEngine', 'Failed to resume audio transport', err)
  }

  try {
    // If the gig is already playing, we don't need to try and resume it.
    // The inner resumeGigPlayback also has this check, but this prevents duplicate triggers from multiple rapid resumeAudio calls.
    if (!audioState.gigIsPaused) return true

    const success = resumeGigPlayback()
    if (!success) {
      audioState.gigIsPaused = true // Revert if failed
    }
    return success
  } catch (err) {
    logger.warn('AudioEngine', 'Failed to resume gig playback', err)
    audioState.gigIsPaused = true // Revert if failed
    return false
  }
}

/**
 * Returns the current Tone transport state.
 * @returns {'started'|'stopped'|'paused'}
 */
export function getTransportState(): 'started' | 'stopped' | 'paused' {
  return Tone.getTransport().state
}

/**
 * Applies global destination mute.
 * @param {boolean} muted - Whether the output destination should be muted.
 * @returns {boolean} The applied mute state.
 */
export function setDestinationMute(muted: boolean): boolean {
  const nextMute = Boolean(muted)
  try {
    Tone.getDestination().mute = nextMute
    return nextMute
  } catch (err) {
    logger.warn('AudioEngine', 'Failed to set destination mute', err)
    try {
      return Tone.getDestination().mute
    } catch {
      return false
    }
  }
}

/**
 * Returns whether ambient OGG playback is currently active.
 * @returns {boolean}
 */
export function isAmbientOggPlaying(): boolean {
  return audioState.ambientSource != null
}

/**
 * Returns the current audio clock time in milliseconds.
 * Uses the Tone.js AudioContext clock so visual elapsed time stays
 * tightly coupled to the audio transport, preventing drift that occurs
 * when mixing Date.now() with Tone scheduling.
 * @returns {number} Current audio time in ms.
 */
export function getAudioTimeMs(): number {
  return Tone.now() * 1000
}

/**
 * Returns the current play request ID.
 * @returns {number} The play request ID.
 */
export function getPlayRequestId(): number {
  return audioState.playRequestId
}

