/**
 * Calculates ticket sales revenue and attendance.
 */
export const calculateTicketIncome = (
  gigData: any = {},
  playerFame = 0,
  modifiers: any = {},
  context: any = {}
) => {
  gigData = gigData || {}
  modifiers = modifiers || {}
  context = context || {}
  // Base draw is ~30%. Fame fills the rest.
  const baseDrawRatio = TICKET_SALES_CONSTANTS.BASE_DRAW_RATIO
  // Fame needs to be ~8x capacity to fill it easily
  const baseCapacity = Math.max(0, gigData.capacity || 0)
  const safeCapacity = Math.max(1, baseCapacity) // Prevent division by zero or negative

  // Logarithmic fame scaling: fame matters more at low levels, flattens at high levels.
  // Denominator scales with venue capacity so large venues require proportionally more fame.
  const fameRatio = Math.min(
    1.0,
    Math.log(Math.max(0, playerFame) + 1) /
      Math.log(safeCapacity * TICKET_SALES_CONSTANTS.FAME_CAPACITY_SCALER + 1)
  )
  let fillRate =
    baseDrawRatio + fameRatio * TICKET_SALES_CONSTANTS.FAME_FILL_WEIGHT

  // Promo Boost
  if (modifiers.promo) fillRate += 0.22

  // Soundcheck Boost (word-of-mouth from quality prep)
  if (modifiers.soundcheck) fillRate += 0.2

  const gigDifficulty = gigData.diff ?? gigData.difficulty
  const daysSinceLastGig = context.daysSinceLastGig
  const hasValidDaysSinceLastGig =
    Number.isFinite(daysSinceLastGig) && daysSinceLastGig > 0

  // Gig frequency vs quality gap penalty
  if (
    context.lastGigDifficulty === gigDifficulty &&
    hasValidDaysSinceLastGig &&
    daysSinceLastGig < 4
  ) {
    fillRate -= 0.15
  }

  // Controversy attendance penalty: -1% per point above 40, max -30%
  const controversyLevel = context.controversyLevel || 0
  if (controversyLevel >= 40) {
    fillRate -= Math.min(0.3, (controversyLevel - 40) * 0.01)
  }

  // Regional reputation bonus/penalty
  const regionRep = context.regionRep || 0
  if (regionRep < 0) {
    fillRate -= Math.min(0.2, Math.abs(regionRep) * 0.002) // -2% per -10 rep, max -20%
  } else if (regionRep > 0) {
    fillRate += Math.min(0.2, regionRep * 0.002) // +2% per +10 rep, max +20%
  }

  // Discounted tickets flag: +10% fill
  if (context.discountedTickets) {
    fillRate += 0.1
  }

  // Price Sensitivity: Higher price reduces attendance slightly unless Fame is very high
  if (!context.discountedTickets && gigData.price > 15) {
    const pricePenalty = (gigData.price - 15) * 0.02 // -2% per Euro over 15
    const mitigation = fameRatio * 0.5
    fillRate -= Math.max(0, pricePenalty - mitigation)
  }

  fillRate = Math.min(1.0, Math.max(0.1, fillRate)) // Clamp 10% - 100%

  const ticketsSold = Math.floor(baseCapacity * fillRate)
  const revenue = Math.max(0, ticketsSold * (Math.max(0, gigData.price) || 0))

  return {
    revenue,
    ticketsSold,
    breakdownItem: {
      labelKey: 'economy:gigIncome.ticketSales.label',
      value: revenue,
      detailKey: 'economy:gigIncome.ticketSales.detail',
      detailParams: { sold: ticketsSold, capacity: baseCapacity }
    }
  }
}

/**
 * Calculates merch sales revenue and costs.
 */
export const calculateMerchIncome = (
  ticketsSold = 0,
  performanceScore = 0,
  gigStats: any = {},
  modifiers: any = {},
  bandInventory: any = {},
  context: any = {}
) => {
  gigStats = gigStats || {}
  modifiers = modifiers || {}
  bandInventory = bandInventory || {}
  context = context || {}
  // Better baseline merch conversion.
  // Smoothly scales from 10% to 40% based on performance
  let buyRate = 0.1 + (performanceScore / 100) * 0.3
  const breakdownItems = []

  if (performanceScore >= 95) {
    buyRate *= 1.25 // S-Rank Bonus
    breakdownItems.push({
      labelKey: 'economy:gigIncome.hypeBonus.label',
      value: 0,
      detailKey: 'economy:gigIncome.hypeBonus.detail'
    })
  } else if (performanceScore < 40) {
    buyRate *= 0.5 // Poor performance penalty
    breakdownItems.push({
      labelKey: 'economy:gigIncome.badShow.label',
      value: 0,
      detailKey: 'economy:gigIncome.badShow.detail'
    })
  }

  if (modifiers.merch) buyRate += 0.1 // Boosted merch table effect to reward investment

  // Loyalty converts to merch sales during controversy
  if ((context?.controversyLevel || 0) >= 40 && (context?.loyalty || 0) >= 20) {
    const loyaltyBuyBonus = Math.min(0.15, (context.loyalty / 100) * 0.2)
    buyRate = Math.min(0.45, buyRate + loyaltyBuyBonus)
    breakdownItems.push({
      labelKey: 'economy:gigIncome.loyalFans.label',
      value: 0,
      detailKey: 'economy:gigIncome.loyalFans.detail'
    })
  }

  // Penalty: Misses drive people away (scaled penalty)
  if (gigStats && gigStats.misses > 0) {
    const missPenalty = Math.min(buyRate * 0.5, gigStats.misses * 0.015)
    buyRate -= missPenalty
  }

  const totalInventory = Math.max(
    0,
    (bandInventory?.shirts || 0) +
      (bandInventory?.hoodies || 0) +
      (bandInventory?.cds || 0) +
      (bandInventory?.patches || 0) +
      (bandInventory?.vinyl || 0)
  )
  const potentialBuyers = Math.floor(
    Math.max(0, ticketsSold) * Math.max(0, buyRate)
  )
  const buyers = Math.min(potentialBuyers, totalInventory)

  // Average Spend per buyer (simplified mix)
  const merchAvgRevenue = 25 // Shirt + Sticker
  const merchAvgCost = 10
  const merchRevenue = buyers * merchAvgRevenue
  const merchCost = buyers * merchAvgCost

  breakdownItems.push({
    labelKey: 'economy:gigIncome.merchSales.label',
    value: merchRevenue,
    detailKey: 'economy:gigIncome.merchSales.detail',
    detailParams: { buyers }
  })

  return {
    revenue: merchRevenue,
    cost: merchCost,
    breakdownItems,
    costItem: {
      labelKey: 'economy:gigExpenses.merchRestock.label',
      value: merchCost,
      detailKey: 'economy:gigExpenses.merchRestock.detail'
    }
  }
}

/**
 * Calculates distance between two nodes or a node and a fallback point.
 * @param {object} nodeA - The target node.
 * @param {object} [nodeB=null] - The source node.
 * @returns {number} The calculated distance.
 */
export const calculateDistance = (nodeA: any, nodeB: any = null) => {
  nodeA = nodeA || {}
  nodeB = nodeB || {}
  const x1 = typeof nodeA?.x === 'number' ? nodeA.x : (nodeA?.venue?.x ?? 50)
  const y1 = typeof nodeA?.y === 'number' ? nodeA.y : (nodeA?.venue?.y ?? 50)

  const x2 =
    nodeB && typeof nodeB.x === 'number' ? nodeB.x : (nodeB?.venue?.x ?? 50)
  const y2 =
    nodeB && typeof nodeB.y === 'number' ? nodeB.y : (nodeB?.venue?.y ?? 50)

  const dx = x1 - x2
  const dy = y1 - y2

  // Distance logic: Relative distance + base cost
  return Math.floor(Math.sqrt(dx * dx + dy * dy) * 5) + 20
}

/**
 * Calculates fuel consumption and cost based on distance and player upgrades.
 * @param {number} dist - The distance in km.
 * @param {object} [playerState=null] - Optional player state for upgrade checks.
 * @param {object} [bandState=null] - Optional band state for trait checks.
 * @returns {object} { fuelLiters, fuelCost }
 */
export const calculateFuelCost = (
  dist: any,
  playerState: any = null,
  bandState: any = null
) => {
  if (dist < 0) return { fuelLiters: 0, fuelCost: 0 }

  let fuelLiters = (dist / 100) * EXPENSE_CONSTANTS.TRANSPORT.FUEL_PER_100KM

  // Check for 'van_tuning' upgrade
  if (
    playerState &&
    playerState.van &&
    playerState.van.upgrades &&
    playerState.van.upgrades.includes('van_tuning')
  ) {
    fuelLiters *= 0.8 // 20% reduction
  }

  // Road Warrior Trait: 15% discount on fuel consumption
  if (bandHasTrait(bandState, 'road_warrior')) {
    fuelLiters *= 0.85
  }

  const fuelCost = Math.floor(
    fuelLiters * EXPENSE_CONSTANTS.TRANSPORT.FUEL_PRICE
  )

  return { fuelLiters, fuelCost }
}

/**
 * Calculates travel expenses.
 * @param {object} node - The target node.
 * @param {object} [fromNode=null] - The source node.
 * @param {object} [playerState=null] - Optional player state for upgrade-aware costs.
 * @param {object} [bandState=null] - Optional band state for trait checks.
 */
export const calculateTravelExpenses = (
  node: any,
  fromNode: any = null,
  playerState: any = null,
  bandState: any = null
) => {
  const dist = calculateDistance(node, fromNode)
  const { fuelLiters } = calculateFuelCost(dist, playerState, bandState)

  const bandSize = bandState?.members?.length || 3
  const fameLevel = playerState?.fameLevel || 0

  // Base food cost
  const foodCost = bandSize * EXPENSE_CONSTANTS.FOOD.FAST_FOOD

  // Keep travel scaling predictable: mild distance pressure, mild fame pressure,
  // and at most a small reserve fee for travelling with a large cash buffer.
  const distanceLogistics = Math.floor(
    (dist / 100) * TRAVEL_LOGISTICS_PER_100KM
  )
  const fameLogistics = Math.floor(fameLevel * TRAVEL_LOGISTICS_PER_FAME_LEVEL)
  const cashReserveFee = Math.min(
    TRAVEL_LOGISTICS_CASH_CAP,
    Math.floor((playerState?.money || 0) / 1000) * 5
  )
  const logisticsCost =
    TRAVEL_LOGISTICS_BASE + distanceLogistics + fameLogistics + cashReserveFee
  const totalCost = foodCost + logisticsCost

  return { dist, fuelLiters, totalCost }
}

/**
 * Calculates the cost to refuel the van to full capacity.
 * @param {number} currentFuel - Current fuel level.
 * @returns {number} Cost in euros.
 */
export const calculateRefuelCost = (currentFuel: any) => {
  const missing = Math.max(
    0,
    EXPENSE_CONSTANTS.TRANSPORT.MAX_FUEL - currentFuel
  )
  return Math.ceil(missing * EXPENSE_CONSTANTS.TRANSPORT.FUEL_PRICE)
}

/**
 * Calculates the cost to repair the van to full condition.
 * @param {number} currentCondition - Current condition (0-100).
 * @returns {number} Cost in euros.
 */
export const calculateRepairCost = (currentCondition: any) => {
  const missing = Math.max(0, 100 - currentCondition)
  return Math.ceil(missing * EXPENSE_CONSTANTS.TRANSPORT.REPAIR_COST_PER_UNIT)
}

/**
 * Calculates the effective ticket price, accounting for any discounts or modifiers.
 * @param {object} gigData - The gig data containing the base price.
 * @param {object} context - Context object containing flags like discountedTickets.
 * @returns {number} The effective ticket price.
 */
export const calculateEffectiveTicketPrice = (
  gigData: any = {},
  context: any = {}
) => {
  if (!gigData) return 0
  gigData = gigData || {}
  context = context || {}
  let price = gigData.price || 0
  if (context.discountedTickets && price > 10) {
    price = Math.floor(price * 0.5)
  }
  return price
}

/**
 * Calculates venue split / promoter cut.
 */
const VENUE_SPLIT_RATES: Record<number, number> = { 3: 0.35, 4: 0.55 }
export const calculateVenueSplit = (ticketsRevenue = 0, gigData: any = {}) => {
  gigData = gigData || {}
  const splitRate =
    gigData.diff >= 5
      ? 0.7
      : Object.hasOwn(VENUE_SPLIT_RATES, gigData.diff)
        ? (VENUE_SPLIT_RATES[gigData.diff as number] ?? 0)
        : 0

  if (splitRate > 0) {
    const splitAmount = Math.floor(Math.max(0, ticketsRevenue) * splitRate)
    return {
      amount: splitAmount,
      expenseItem: {
        labelKey: 'economy:gigExpenses.venueSplit.label',
        value: splitAmount,
        detailKey: 'economy:gigExpenses.venueSplit.detail',
        detailParams: { rate: splitRate * 100 }
      }
    }
  }
  return { amount: 0, expenseItem: null }
}

/**
 * Calculates guarantee / base pay.
 */
export const calculateGuarantee = (gigData: any = {}) => {
  gigData = gigData || {}
  const pay = Math.max(0, gigData.pay || 0)
  if (pay > 0) {
    return {
      amount: pay,
      incomeItem: {
        labelKey: 'economy:gigIncome.guarantee.label',
        value: pay,
        detailKey: 'economy:gigIncome.guarantee.detail'
      }
    }
  }
  return { amount: 0, incomeItem: null }
}

/**
 * Calculates bar cut revenue.
 */
export const calculateBarCut = (ticketsSold = 0, modifiers: any = {}) => {
  modifiers = modifiers || {}
  const barRate = modifiers.guestlist ? BAR_RATE_VIP : BAR_RATE_NORMAL
  const barPercent = Math.round(barRate * 100)
  const barRevenue = Math.max(
    0,
    Math.floor(ticketsSold * AVG_SPEND_PER_PERSON_AT_BAR * barRate)
  )
  return {
    revenue: barRevenue,
    incomeItem: {
      labelKey: modifiers.guestlist
        ? 'economy:gigIncome.vipBarRevenue.label'
        : 'economy:gigIncome.barCut.label',
      value: barRevenue,
      detailKey: modifiers.guestlist
        ? 'economy:gigIncome.vipBarRevenue.detail'
        : 'economy:gigIncome.barCut.detail',
      detailParams: { percent: barPercent }
    }
  }
}

/**
 * Calculates sponsorship bonuses.
 */
export const calculateSponsorshipBonuses = (gigStats: any = {}) => {
  gigStats = gigStats || {}
  const bonuses = []
  let totalBonus = 0

  if (gigStats) {
    if (gigStats.misses === 0) {
      const bonus = 200
      bonuses.push({
        labelKey: 'economy:gigIncome.techSponsor.label',
        value: bonus,
        detailKey: 'economy:gigIncome.techSponsor.detail'
      })
      totalBonus += bonus
    }
    if (gigStats.peakHype >= 100) {
      const bonus = 150
      bonuses.push({
        labelKey: 'economy:gigIncome.beerSponsor.label',
        value: bonus,
        detailKey: 'economy:gigIncome.beerSponsor.detail'
      })
      totalBonus += bonus
    }
  }

  return { totalBonus, incomeItems: bonuses }
}

/**
 * Calculates expenses for the gig.
 */
export const calculateGigExpenses = (modifiers: any = {}) => {
  modifiers = modifiers || {}
  const expenses: { total: number; breakdown: FinancialBreakdownItem[] } = {
    total: 0,
    breakdown: []
  }

  // Operational Expenses (Modifiers)
  // Transport and subsistence are now exclusively handled during travel phase.

  // Modifiers (Budget items)
  if (modifiers.catering) {
    expenses.breakdown.push({
      labelKey: 'economy:gigExpenses.catering.label',
      value: MODIFIER_COSTS.catering,
      detailKey: 'economy:gigExpenses.catering.detail'
    })
    expenses.total += MODIFIER_COSTS.catering
  }

  if (modifiers.promo) {
    expenses.breakdown.push({
      labelKey: 'economy:gigExpenses.socialAds.label',
      value: MODIFIER_COSTS.promo,
      detailKey: 'economy:gigExpenses.socialAds.detail'
    })
    expenses.total += MODIFIER_COSTS.promo
  }

  if (modifiers.merch) {
    expenses.breakdown.push({
      labelKey: 'economy:gigExpenses.merchStand.label',
      value: MODIFIER_COSTS.merch,
      detailKey: 'economy:gigExpenses.merchStand.detail'
    })
    expenses.total += MODIFIER_COSTS.merch
  }

  if (modifiers.soundcheck) {
    expenses.breakdown.push({
      labelKey: 'economy:gigExpenses.soundcheck.label',
      value: MODIFIER_COSTS.soundcheck,
      detailKey: 'economy:gigExpenses.soundcheck.detail'
    })
    expenses.total += MODIFIER_COSTS.soundcheck
  }

  if (modifiers.guestlist) {
    expenses.breakdown.push({
      labelKey: 'economy:gigExpenses.guestList.label',
      value: MODIFIER_COSTS.guestlist,
      detailKey: 'economy:gigExpenses.guestList.detail'
    })
    expenses.total += MODIFIER_COSTS.guestlist
  }

  return expenses
}

/**
 * Calculates the full financial breakdown of a gig with Fame Scaling and Hype bonuses.
 * @param {object} params - Parameters object
 * @param {object} params.gigData - { capacity, price, pay (guarantee), dist, diff }
 * @param {number} params.performanceScore - 0 to 100
 * @param {object} params.modifiers - { merch: bool, promo: bool, catering: bool, soundcheck: bool, guestlist: bool }
 * @param {object} params.bandInventory - { shirts, hoodies, etc }
 * @param {object|number} params.playerStateOrFame - Player state object or just fame (number) for legacy support
 * @param {object} params.gigStats - Detailed gig stats (misses, peakHype, etc)
 */
export const calculateGigFinancials = ({
  gigData,
  performanceScore,
  modifiers,
  bandInventory,
  playerState,
  gigStats,
  context = {}
}: any) => {
  const playerFame = playerState?.fame || 0

  logger.debug('Economy', 'Calculating Gig Financials', {
    gig: gigData.name,
    score: performanceScore,
    fame: playerFame
  })

  const effectivePrice = calculateEffectiveTicketPrice(gigData, context)
  const effectiveGigData = { ...gigData, price: effectivePrice }

  const report: {
    income: { total: number; breakdown: FinancialBreakdownItem[] }
    expenses: { total: number; breakdown: FinancialBreakdownItem[] }
    net: number
  } = {
    income: { total: 0, breakdown: [] },
    expenses: { total: 0, breakdown: [] },
    net: 0
  }

  // Normalize context: some callers flatten social fields to top-level while
  // also passing the full social sub-object. Support both shapes defensively.
  const ctxSocial = context?.social ?? {}

  // 1. Ticket Sales
  // Apply automated promo from zealotry to tickets
  const zealotry = context.zealotry ?? ctxSocial.zealotry ?? 0
  const effectiveModifiers = { ...modifiers }
  if (zealotry >= ZEALOTRY_PROMO_THRESHOLD) {
    effectiveModifiers.promo = true
  }

  const tickets = calculateTicketIncome(
    effectiveGigData,
    playerFame,
    effectiveModifiers,
    context
  )
  report.income.breakdown.push(tickets.breakdownItem)
  report.income.total += tickets.revenue

  // Venue Split / Promoter Cut
  const venueSplit = calculateVenueSplit(tickets.revenue, gigData)
  if (venueSplit.expenseItem) {
    report.expenses.breakdown.push(venueSplit.expenseItem)
    report.expenses.total += venueSplit.amount
  }

  // 2. Guarantee
  const guarantee = calculateGuarantee(gigData)
  if (guarantee.incomeItem) {
    report.income.breakdown.push(guarantee.incomeItem)
    report.income.total += guarantee.amount
  }

  // 3. Cult Donations (Zealotry)
  const { passiveIncome } = calculateZealotryEffects(zealotry)
  if (passiveIncome > 0) {
    report.income.breakdown.push({
      labelKey: 'economy:cultDonations',
      value: passiveIncome
    })
    report.income.total += passiveIncome
  }

  // 4. Merch Sales
  const merch = calculateMerchIncome(
    tickets.ticketsSold,
    performanceScore,
    gigStats,
    modifiers,
    bandInventory,
    context
  )
  report.income.breakdown.push(...merch.breakdownItems)
  report.income.total += merch.revenue
  report.expenses.breakdown.push(merch.costItem)
  report.expenses.total += merch.cost

  // 5. Bar Cut
  const barCut = calculateBarCut(tickets.ticketsSold, modifiers)
  report.income.breakdown.push(barCut.incomeItem)
  report.income.total += barCut.revenue

  // 6. Expenses (Modifiers)
  const costModifiers = { ...modifiers }
  // If zealotry is high, player does not pay for promo even if they explicitly checked it
  if (zealotry >= ZEALOTRY_PROMO_THRESHOLD) {
    costModifiers.promo = false
  }

  const operationalExpenses = calculateGigExpenses(costModifiers)
  report.expenses.breakdown.push(...operationalExpenses.breakdown)
  report.expenses.total += operationalExpenses.total

  // Active Deal Per-Gig Payout
  const activeDeals = ctxSocial.activeDeals ?? []
  for (let i = 0; i < activeDeals.length; i++) {
    const activeDeal = activeDeals[i]
    if (
      activeDeal.type === 'SPONSORSHIP' &&
      activeDeal.offer &&
      activeDeal.offer.perGig
    ) {
      const perGigPayout = activeDeal.offer.perGig
      report.income.breakdown.push({
        labelKey: 'economy:gigIncome.brandSponsor.label',
        value: perGigPayout,
        detailKey: 'economy:gigIncome.brandSponsor.detail'
      })
      report.income.total += perGigPayout
    }
  }

  // 6. Sponsorship Bonuses
  const sponsorshipBonuses = calculateSponsorshipBonuses(gigStats)
  if (sponsorshipBonuses.incomeItems.length > 0) {
    report.income.breakdown.push(...sponsorshipBonuses.incomeItems)
    report.income.total += sponsorshipBonuses.totalBonus
  }

  // 7. Management Cut (fame-progressive: 0% at fame=0, full 15% at fame≥200)
  const effectiveCutRate = MANAGEMENT_CUT_RATE * Math.min(1, playerFame / 200)
  const managementCut = Math.floor(report.income.total * effectiveCutRate)
  if (managementCut > 0) {
    report.expenses.breakdown.push({
      labelKey: 'economy:gigExpenses.managementFee.label',
      value: managementCut,
      detailKey: 'economy:gigExpenses.managementFee.detail',
      detailParams: { rate: Math.round(effectiveCutRate * 100) }
    })
    report.expenses.total += managementCut
  }

  report.net = Math.floor(
    (report.income.total - report.expenses.total) * GLOBAL_PAYOUT_NERF
  )

  // 8. Hard gig net cap — prevents single large-venue outlier from breaking economy
  if (report.net > MAX_GIG_NET) {
    const overageFee = report.net - MAX_GIG_NET
    report.expenses.breakdown.push({
      labelKey: 'economy:gigExpenses.overageFee.label',
      value: overageFee,
      detailKey: 'economy:gigExpenses.overageFee.detail'
    })
    report.expenses.total += overageFee
    report.net = MAX_GIG_NET
  }

  logger.info('Economy', 'Gig Report Generated', {
    net: report.net,
    income: report.income.total,
    expenses: report.expenses.total
  })
  return report
}

/**
 * Determines whether the run should end due to insolvency.
 * @param {number} newMoney - Player money after applying earnings/losses.
 * @param {number} netIncome - Net income from the gig (optional context).
 * @returns {boolean} True when player is bankrupt.
 * @throws {TypeError} If newMoney is not a finite number.
 */
export const shouldTriggerBankruptcy = (newMoney: any, netIncome: any) => {
  const val = Number(newMoney)
  if (!Number.isFinite(val)) {
    throw new TypeError('newMoney must be a finite number')
  }

  // If player has money left, they are not bankrupt.
  if (val > 0) return false

  // If negative balance, instant bankruptcy (debt is fatal).
  // This explicitly catches un-clamped inputs.
  if (val < 0) return true

  // If exactly 0, check if we are bleeding money (netIncome < 0).
  // If netIncome is undefined, default to 0 (assume break-even/safe).
  const income = netIncome ?? 0

  // Bankrupt if at 0 money and net income was strictly negative.
  return income < 0
}

/**
 * Calculates effects of Travel Minigame results.
 * @param {number} damageTaken - Total damage taken.
 * @param {string[]} itemsCollected - Array of collected item types.
 * @returns {object} { conditionLoss, fuelBonus }
 */
export const calculateTravelMinigameResult = (
  damageTaken: any,
  itemsCollected: any
) => {
  // 50% damage scaling: 100 damage -> 50 condition loss
  const conditionLoss = Math.floor(Math.max(0, damageTaken) / 2)

  // Fuel bonus re-enabled: each fuel item grants 0.5 liters of fuel bonus
  let fuelItems = 0
  if (Array.isArray(itemsCollected)) {
    for (const item of itemsCollected) {
      if (item === 'FUEL') fuelItems++
    }
  }
  const fuelBonus = fuelItems * 0.5

  return { conditionLoss, fuelBonus }
}

/**
 * Calculates effects of Roadie Minigame results.
 * @param {number} equipmentDamage - Total equipment damage.
 * @param {object} bandState - Current band traits/state used by bandHasTrait.
 * @returns {object} { stress, repairCost }
 */
export const calculateRoadieMinigameResult = (
  equipmentDamage: any,
  bandState: any
) => {
  const safeDamage = Math.max(0, equipmentDamage)
  const stress = Math.floor(safeDamage / 5)
  let repairCost = Math.floor(safeDamage * 2)

  // Gear Nerd Trait: 20% discount on repairs
  if (bandHasTrait(bandState, 'gear_nerd')) {
    repairCost = Math.floor(repairCost * 0.8)
  }

  return { stress, repairCost }
}

/**
 * Calculates outcome for Amp Calibration minigame
 * @param {number} score - 0 to 100
 * @param {Object} bandState
 * @returns {Object} { stress, reward }
 */
export const calculateAmpCalibrationResult = (score: any, bandState: any) => {
  let numScore = Number(score)
  if (!Number.isFinite(numScore)) {
    numScore = 0
  }
  const safeScore = Math.max(0, Math.min(100, numScore))
  let stress = 0
  let reward = 0

  if (safeScore < 50) {
    // Failure or poor performance
    stress = Math.floor((50 - safeScore) / 2)
  } else {
    // Success
    reward = Math.floor(safeScore)

    // Tech Wizard trait increases rewards
    if (bandHasTrait(bandState, 'tech_wizard')) {
      reward = Math.floor(reward * 1.5)
    }
  }

  return { stress, reward }
}

/**
 * Calculates outcome for Kabelsalat minigame
 * @param {Object} results - { isPoweredOn: boolean, timeLeft: number }
 * @param {Object} bandState
 * @returns {Object} { stress, reward }
 */
export const calculateKabelsalatMinigameResult = (
  results: any,
  bandState: any
) => {
  let stress = 0
  let reward = 0

  if (!results.isPoweredOn) {
    // Failure! Stress for everyone.
    stress = 15
  } else {
    // Success! Reward based on time remaining
    const validTimeLeft = Number.isFinite(results.timeLeft)
      ? results.timeLeft
      : 0
    const timeBonus = Math.max(0, Math.floor(validTimeLeft / 5))
    reward = Math.max(0, 60 + timeBonus * 15) // Base 60, scaling better for quick completion

    // Tech Wizard trait increases rewards
    if (bandHasTrait(bandState, 'tech_wizard')) {
      reward = Math.floor(reward * 1.5)
    }
  }

  return { stress, reward }
}

import { hasTrait } from './traitLogic'
import { EXPENSE_CONSTANTS } from './economyEngine'
import { logger } from './logger'

/**
 * Clamps a value to be at least 0.
 *
 * @param {number} value - Candidate value.
 * @returns {number} Clamped value ensuring non-negative.
 */
export const clampNonNegative = (value: number): number => {
  if (!Number.isFinite(value)) return 0
  return Math.max(0, value)
}

export const isPlainObject = (
  value: unknown
): value is Record<string, unknown> =>
  typeof value === 'object' && value !== null && !Array.isArray(value)

/**
 * Derives fame level from raw fame.
 * @param {number} fame - Raw fame amount.
 * @returns {number} Derived fame level.
 */
export const calculateFameLevel = (fame: number): number => {
  const clampedFame = clampNonNegative(fame)
  return Math.floor(clampedFame / 100)
}

/**
 * Clamps a band member's stamina to be between 0 and their staminaMax (default 100).
 *
 * @param {number} stamina - Candidate stamina value.
 * @param {number} [staminaMax=100] - The member's maximum stamina.
 * @returns {number} Clamped stamina value.
 */
export const clampMemberStamina = (
  stamina: number,
  staminaMax = 100
): number => {
  if (!Number.isFinite(stamina)) return 0
  const resolvedStaminaMax = Number.isFinite(staminaMax) ? staminaMax : 100
  return Math.max(0, Math.min(resolvedStaminaMax, Math.floor(stamina)))
}

/**
 * Clamps a band member's mood to be between 0 and 100.
 *
 * @param {number} mood - Candidate mood value.
 * @returns {number} Clamped mood value.
 */
export const clampMemberMood = (mood: number): number => {
  if (!Number.isFinite(mood)) return 0
  return Math.max(0, Math.min(100, Math.floor(mood)))
}

/**
 * Clamps player fame to be at least 0.
 *
 * @param {number} fame - Candidate fame value.
 * @returns {number} Clamped non-negative fame value.
 */
export const clampPlayerFame = (fame: number): number => {
  if (!Number.isFinite(fame)) return 0
  return Math.max(0, Math.floor(fame))
}

export const FAME_PROGRESS_CONSTANTS = Object.freeze({
  GIG_BASE_REWARD: 100,
  GIG_SCORE_MULTIPLIER: 10,
  DIMINISHING_RETURNS_START: 30000,
  DIMINISHING_RETURNS_RATE: 0.0001
})

/**
 * Calculates the raw fame reward for a successful gig before any diminishing returns.
 * Tuned so the full fame catalog remains reachable in roughly 20-30 strong gigs.
 *
 * @param {number} performanceScore - Gig performance score.
 * @returns {number} Raw gig fame reward.
 */
export const calculateGigFameReward = (performanceScore: number): number => {
  const safePerformanceScore = Number.isFinite(performanceScore)
    ? Math.max(0, performanceScore)
    : 0

  return (
    FAME_PROGRESS_CONSTANTS.GIG_BASE_REWARD +
    Math.floor(
      safePerformanceScore * FAME_PROGRESS_CONSTANTS.GIG_SCORE_MULTIPLIER
    )
  )
}

/**
 * Calculates fame gain with exponential diminishing returns.
 * Ensures the logic is synced across the app and simulation.
 * @param {number} rawGain - The uncapped fame gain calculated from performance.
 * @param {number} currentFame - The player's current fame.
 * @param {number} [maxGain=2000] - Hard cap on raw gain.
 * @returns {number} The final damped fame gain.
 */
export const calculateFameGain = (
  rawGain: number,
  currentFame: number,
  maxGain = 2000
): number => {
  let fameGain = Math.min(maxGain, rawGain)
  const prevFame = currentFame ?? 0

  if (
    fameGain > 0 &&
    prevFame > FAME_PROGRESS_CONSTANTS.DIMINISHING_RETURNS_START
  ) {
    const diminishingMultiplier = Math.exp(
      -(prevFame - FAME_PROGRESS_CONSTANTS.DIMINISHING_RETURNS_START) *
        FAME_PROGRESS_CONSTANTS.DIMINISHING_RETURNS_RATE
    )
    fameGain = Math.max(1, Math.round(fameGain * diminishingMultiplier))
  }

  return fameGain
}

/**
 * Clamps a social controversy level to be between 0 and 100.
 *
 * @param {number} level - Candidate controversy level.
 * @returns {number} Clamped controversy level in range [0, 100].
 */
export const clampControversyLevel = (level: number): number => {
  if (!Number.isFinite(level)) return 0
  const safeLevel = Math.floor(level)
  return Math.max(0, Math.min(100, safeLevel))
}

/**
 * Clamps player money to a safe, non-negative integer.
 * Prevents negative balances and ensures integer boundaries.
 *
 * @param {number} money - Candidate money value.
 * @returns {number} Clamped money value ensuring non-negative integer.
 */
export const clampPlayerMoney = (money: number): number => {
  if (!Number.isFinite(money)) return 0
  return Math.floor(Math.max(0, money))
}

// Shared Balance Constants
export const BALANCE_CONSTANTS = {
  FAME_LOSS_BAD_GIG: 9,
  MAX_FAME_GAIN: 2000,
  LOW_HARMONY_THRESHOLD: 15,
  LOW_HARMONY_CANCELLATION_CHANCE: 0.2,
  // Miss-penalty on bad gigs (perfScore < 62)
  MISS_TOLERANCE: 8,
  MISS_PENALTY_RATE: 1.2, // fame loss per excess miss (was 0.5)
  MISS_MONEY_PENALTY: 12, // €12 per excess miss (direct money deduction)
  // Sponsor daily payout range (fame-scaled)
  SPONSORSHIP_PAYOUT_FLOOR: 200,
  SPONSORSHIP_PAYOUT_CAP: 380,
  // Wealth-scaled daily drain thresholds
  WEALTH_DRAIN_THRESHOLD: 2000,
  WEALTH_DRAIN_CHANCE: 0.12,
  WEALTH_DRAIN_MIN_RATE: 0.015,
  WEALTH_DRAIN_MAX_RATE: 0.05
}

export const RELATIONSHIP_GRUDGE_HOLDER_MULTIPLIER = 1.5
export const RELATIONSHIP_PEACEMAKER_POSITIVE_MULTIPLIER = 1.5
export const RELATIONSHIP_PEACEMAKER_NEGATIVE_MULTIPLIER = 0.5
export const RELATIONSHIP_DEFAULT_SCORE = 50
export const RELATIONSHIP_MIN_SCORE = 0
export const RELATIONSHIP_MAX_SCORE = 100

/**
 * Clamps band harmony to the canonical gameplay range.
 *
 * @param {number} harmony - Candidate harmony value.
 * @returns {number} Clamped harmony value in range [1, 100].
 */
export const clampBandHarmony = (harmony: number): number => {
  if (!Number.isFinite(harmony)) return 1
  const safeHarmony = Math.floor(harmony)
  return Math.max(1, Math.min(100, safeHarmony))
}

/**
 * Clamps van condition to the allowed percentage (0-100).
 *
 * @param {number} condition - Candidate condition value.
 * @returns {number} Clamped condition value.
 */
export const clampVanCondition = (condition: number): number => {
  if (!Number.isFinite(condition)) return 0
  return Math.floor(Math.max(0, Math.min(100, condition)))
}

/**
 * Clamps van fuel to the allowed capacity.
 *
 * @param {number} fuel - Candidate fuel value.
 * @param {number} maxFuel - Maximum capacity.
 * @returns {number} Clamped fuel value.
 */
export const clampVanFuel = (
  fuel: number,
  maxFuel = EXPENSE_CONSTANTS.TRANSPORT.MAX_FUEL
): number => {
  if (!Number.isFinite(fuel)) return 0
  return Math.max(0, Math.min(maxFuel, fuel))
}

/**
 * Applies an inventory delta to a single inventory slot.
 * @param {boolean|number|undefined} currentValue - Existing inventory value.
 * @param {boolean|number} deltaValue - Delta to apply.
 * @returns {boolean|number|undefined} Updated inventory value.
 */
export const applyInventoryItemDelta = (
  currentValue: boolean | number | undefined,
  deltaValue: boolean | number
): boolean | number | undefined => {
  if (deltaValue === true || deltaValue === false) {
    return deltaValue
  }

  if (typeof deltaValue === 'number') {
    const currentCount = typeof currentValue === 'number' ? currentValue : 0
    return Math.max(0, currentCount + deltaValue)
  }

  return currentValue
}

/**
 * A hardened Set of prohibited object property keys used during state-merge operations.
 * Explicitly guards against prototype pollution vulnerabilities by blocking recursive assignment
 * into sensitive prototype traversal chains (e.g. `__proto__`, `constructor`, `prototype`).
 * Usage ensures event deltas cannot maliciously or accidentally mutate the global Object space.
 */
const FORBIDDEN_KEYS = new Set(['__proto__', 'constructor', 'prototype'])
export const isForbiddenKey = (key: string): boolean => FORBIDDEN_KEYS.has(key)

/**
 * Applies event delta changes to the current game state.
 * Prevents prototype pollution and merges object properties.
 *
 * @param {object} state - Current game state.
 * @param {object} delta - Event delta payload.
 * @returns {object} Updated game state.
 */

const calculateClampedStatDelta = (
  currentValue: number | null | undefined,
  deltaValue: number
): number => {
  const baseValue = typeof currentValue === 'number' ? currentValue : 0
  const nextValue = Math.max(0, baseValue + deltaValue)
  return nextValue - baseValue
}

const calculateClampedControversyDelta = (
  currentValue: number | null | undefined,
  deltaValue: number
): number => {
  const baseValue = typeof currentValue === 'number' ? currentValue : 0
  const nextValue = clampControversyLevel(baseValue + deltaValue)
  return nextValue - baseValue
}

/**
 * Copies enumerable own properties from source to a new object, filtering out forbidden keys.
 * @param {object} source - Source object to copy from.
 * @returns {object} New object with filtered properties.
 */
type FilteredRecord = Record<string, unknown>

const copyFilteredProperties = (source: unknown): FilteredRecord => {
  if (typeof source !== 'object' || source === null) return Object.create(null)

  // Explicit check for prototype pollution before copying properties
  if (
    Object.hasOwn(source, '__proto__') ||
    Object.hasOwn(source, 'constructor') ||
    Object.hasOwn(source, 'prototype')
  ) {
    logger?.warn?.(
      'Security',
      'Blocked attempt to copy prototype properties in copyFilteredProperties'
    )
  }

  // Create an object with no prototype to safely copy properties into
  const destination: FilteredRecord = Object.create(null)
  const sourceRecord = source as Record<string, unknown>

  for (const key in sourceRecord) {
    if (!Object.hasOwn(sourceRecord, key)) continue
    if (!isForbiddenKey(key)) {
      destination[key] = sourceRecord[key]
    }
  }
  return destination
}

export const calculateAppliedDelta = (state: any, delta: any): any => {
  const applied: any = { player: {}, band: {}, social: {} }

  if (delta.flags) {
    applied.flags = copyFilteredProperties(delta.flags)
  } else {
    applied.flags = {}
  }

  if (delta.player) {
    if (typeof delta.player.money === 'number') {
      const currentMoney = Math.max(
        0,
        typeof state.player?.money === 'number' ? state.player.money : 0
      )
      const nextMoney = clampPlayerMoney(currentMoney + delta.player.money)
      applied.player.money = nextMoney - currentMoney
    }
    if (typeof delta.player.time === 'number') {
      applied.player.time = delta.player.time // time is unbounded
    }
    if (typeof delta.player.fame === 'number') {
      const currentFame = Math.max(
        0,
        typeof state.player?.fame === 'number' ? state.player.fame : 0
      )
      const nextFame = clampPlayerFame(currentFame + delta.player.fame)
      applied.player.fame = nextFame - currentFame
    }
    const scoreDelta =
      typeof delta.player?.score === 'number'
        ? delta.player.score
        : typeof delta.score === 'number'
          ? delta.score
          : 0
    if (scoreDelta !== 0) {
      const currentScore =
        typeof state.player?.score === 'number' ? state.player.score : 0
      const nextScore = Math.max(0, currentScore + scoreDelta)
      applied.score = nextScore - currentScore
    }
    if (delta.player.van) {
      applied.player.van = {}
      if (typeof delta.player.van.fuel === 'number') {
        const currentFuel =
          typeof state.player?.van?.fuel === 'number'
            ? state.player.van.fuel
            : 0
        const nextFuel = clampVanFuel(currentFuel + delta.player.van.fuel)
        applied.player.van.fuel = nextFuel - currentFuel
      }
      if (typeof delta.player.van.condition === 'number') {
        const currentCondition =
          typeof state.player?.van?.condition === 'number'
            ? state.player.van.condition
            : 0
        const nextCondition = clampVanCondition(
          currentCondition + delta.player.van.condition
        )
        applied.player.van.condition = nextCondition - currentCondition
      }
    }
    if (typeof delta.player.day === 'number') {
      applied.player.day = delta.player.day
    }
    if (delta.player.stats) {
      applied.player.stats = copyFilteredProperties(delta.player.stats)
    }
  }

  if (delta.social) {
    if (typeof delta.social.controversyLevel === 'number') {
      applied.social.controversyLevel = calculateClampedControversyDelta(
        state.social?.controversyLevel,
        delta.social.controversyLevel
      )
    }
    if (typeof delta.social.viral === 'number') {
      applied.social.viral = calculateClampedStatDelta(
        state.social?.viral,
        delta.social.viral
      )
    }
    if (typeof delta.social.loyalty === 'number') {
      applied.social.loyalty = calculateClampedStatDelta(
        state.social?.loyalty,
        delta.social.loyalty
      )
    }
  }

  if (delta.band) {
    if (typeof delta.band.harmony === 'number') {
      const currentHarmony = clampBandHarmony(state.band?.harmony ?? 1)
      const nextHarmony = clampBandHarmony(currentHarmony + delta.band.harmony)
      applied.band.harmony = nextHarmony - currentHarmony
    }

    // Inventory
    if (delta.band.inventory) {
      applied.band.inventory = {}
      // Optimization: using Object.keys avoids prototype chain traversal and Object.hasOwn checks
      const inventoryKeys = Object.keys(delta.band.inventory)
      for (let i = 0; i < inventoryKeys.length; i++) {
        const itemId = inventoryKeys[i]
        if (!itemId) continue
        if (isForbiddenKey(itemId)) continue

        const qty = delta.band.inventory[itemId]
        const currentCount =
          typeof state.band?.inventory?.[itemId] === 'number'
            ? state.band.inventory[itemId]
            : 0

        if (typeof qty === 'number') {
          if (qty !== 0) {
            const nextCount = Math.max(0, currentCount + qty)
            const actualChange = nextCount - currentCount
            if (actualChange !== 0) {
              applied.band.inventory[itemId] = actualChange
            }
          }
        } else if (qty === true) {
          applied.band.inventory[itemId] = true
        } else if (qty === false) {
          if (currentCount > 0) {
            applied.band.inventory[itemId] = -currentCount
          } else {
            applied.band.inventory[itemId] = false
          }
        }
      }
    }

    const membersDelta =
      delta.band.membersDelta !== undefined
        ? delta.band.membersDelta
        : delta.band.members

    if (membersDelta) {
      const isArrayDelta = Array.isArray(membersDelta)
      const members = Array.isArray(state.band?.members)
        ? state.band.members
        : []

      const computedMembersDelta: FilteredRecord[] = []

      for (let i = 0; i < members.length; i++) {
        const member = members[i]
        const rawMemberDelta = isArrayDelta ? membersDelta[i] : membersDelta
        const mDelta =
          rawMemberDelta && typeof rawMemberDelta === 'object'
            ? copyFilteredProperties(rawMemberDelta)
            : Object.create(null)
        if (!member) {
          computedMembersDelta.push(Object.create(null))
          continue
        }

        const moodChange =
          typeof mDelta.moodChange === 'number' ? mDelta.moodChange : 0
        const staminaChange =
          typeof mDelta.staminaChange === 'number' ? mDelta.staminaChange : 0

        const currentMood = typeof member.mood === 'number' ? member.mood : 0
        const currentStamina =
          typeof member.stamina === 'number' ? member.stamina : 0
        const staminaMax =
          typeof member.staminaMax === 'number' ? member.staminaMax : 100

        const newMood = clampMemberMood(currentMood + moodChange)
        const newStamina = clampMemberStamina(
          currentStamina + staminaChange,
          staminaMax
        )

        const actualMoodChange = newMood - currentMood
        const actualStaminaChange = newStamina - currentStamina

        // Keep all other properties of the original delta, override only mood and stamina if they exist
        const newDelta = copyFilteredProperties(mDelta)
        if (typeof mDelta.moodChange === 'number')
          newDelta.moodChange = actualMoodChange
        if (typeof mDelta.staminaChange === 'number')
          newDelta.staminaChange = actualStaminaChange

        computedMembersDelta.push(newDelta)
      }

      // We always resolve to an array delta because global deltas apply differently to each member based on clamps
      applied.band.membersDelta = computedMembersDelta
    }

    if (typeof delta.band.luck === 'number') {
      const currentLuck =
        typeof state.band?.luck === 'number' ? state.band.luck : 0
      const nextLuck = Math.max(0, currentLuck + delta.band.luck)
      applied.band.luck = nextLuck - currentLuck
    }

    if (typeof delta.band.skill === 'number') {
      const members = Array.isArray(state.band?.members)
        ? state.band.members
        : []
      let totalSkillDelta = 0
      applied.band.members = []
      for (let i = 0; i < members.length; i++) {
        const currentSkill =
          members[i].baseStats && typeof members[i].baseStats.skill === 'number'
            ? members[i].baseStats.skill
            : 5
        const nextSkill = Math.max(
          1,
          Math.min(10, currentSkill + delta.band.skill)
        )
        const memberDelta = nextSkill - currentSkill
        applied.band.members.push({ skill: memberDelta })
        totalSkillDelta += memberDelta
      }
      if (members.length > 0) {
        applied.band.skill = Math.round(totalSkillDelta / members.length)
      }
    }

    if (delta.band.relationshipChange) {
      if (Array.isArray(delta.band.relationshipChange)) {
        applied.band.relationshipChange = [...delta.band.relationshipChange]
      } else {
        applied.band.relationshipChange = copyFilteredProperties(
          delta.band.relationshipChange
        )
      }
    }
  }

  return applied
}

/**
 * Calculates the relationship change between members.
 *
 * @param {object} change - The relationship change data.
 * @param {string} memberName - The name of the member being evaluated.
 * @param {boolean} hasGrudgeHolder - If the member has grudge_holder trait.
 * @param {boolean} hasPeacemaker - If the member has peacemaker trait.
 * @param {object} currentRelationships - The current relationships of the member.
 * @returns {object|null} The calculated change or null if none.
 */
export const calculateMemberRelationshipChange = (
  change: any,
  memberName: string,
  hasGrudgeHolder: boolean,
  hasPeacemaker: boolean,
  currentRelationships: Record<string, number>
): { other: string; newScore: number } | null => {
  const isM1 = change.member1 === memberName
  const isM2 = change.member2 === memberName

  if (!isM1 && !isM2) return null

  const other = isM1 ? change.member2 : change.member1
  if (isForbiddenKey(other)) return null

  let amount = change.change
  // Apply traits
  if (amount < 0 && hasGrudgeHolder) {
    amount *= RELATIONSHIP_GRUDGE_HOLDER_MULTIPLIER
  }
  if (amount > 0 && hasPeacemaker) {
    amount *= RELATIONSHIP_PEACEMAKER_POSITIVE_MULTIPLIER
  }
  if (amount < 0 && hasPeacemaker) {
    amount *= RELATIONSHIP_PEACEMAKER_NEGATIVE_MULTIPLIER
  }

  const currentScore = currentRelationships[other] ?? RELATIONSHIP_DEFAULT_SCORE
  const newScore = Math.max(
    RELATIONSHIP_MIN_SCORE,
    Math.min(RELATIONSHIP_MAX_SCORE, Math.round(currentScore + amount))
  )

  return { other, newScore }
}

export const applyEventDelta = (state: any, delta: any): any => {
  const nextState: any = { ...state }

  if (delta.player) {
    const nextPlayer = { ...nextState.player }
    if (typeof delta.player.money === 'number') {
      const nextMoney = clampPlayerMoney(nextPlayer.money + delta.player.money)
      nextPlayer.money = nextMoney
    }
    if (typeof delta.player.time === 'number') {
      nextPlayer.time = nextPlayer.time + delta.player.time
    }
    if (typeof delta.player.fame === 'number') {
      nextPlayer.fame = clampPlayerFame(nextPlayer.fame + delta.player.fame)
      nextPlayer.fameLevel = calculateFameLevel(nextPlayer.fame)
    }
    const scoreDelta =
      typeof delta.player.score === 'number'
        ? delta.player.score
        : typeof delta.score === 'number'
          ? delta.score
          : 0

    if (scoreDelta !== 0) {
      const boundedScore = clampNonNegative(nextPlayer.score)
      nextPlayer.score = boundedScore + scoreDelta
    }

    // Player Stats
    if (delta.player.stats) {
      nextPlayer.stats = { ...nextPlayer.stats }
      const statKeys = Object.keys(delta.player.stats)
      for (let i = 0; i < statKeys.length; i++) {
        const key = statKeys[i]
        if (!key) continue
        if (isForbiddenKey(key)) continue

        if (typeof delta.player.stats[key] === 'number') {
          const boundedStat = clampNonNegative(nextPlayer.stats[key])
          nextPlayer.stats[key] = boundedStat + delta.player.stats[key]
        } else if (
          typeof delta.player.stats[key] === 'string' ||
          typeof delta.player.stats[key] === 'boolean'
        ) {
          nextPlayer.stats[key] = delta.player.stats[key]
        }
      }
    }

    if (delta.player.van) {
      const nextVan = { ...nextPlayer.van }
      if (typeof delta.player.van.fuel === 'number') {
        nextVan.fuel = clampVanFuel(nextVan.fuel + delta.player.van.fuel)
      }
      if (typeof delta.player.van.condition === 'number') {
        const nextCondition = clampVanCondition(
          nextVan.condition + delta.player.van.condition
        )
        nextVan.condition = nextCondition
      }
      nextPlayer.van = nextVan
    }
    if (delta.player.location) nextPlayer.location = delta.player.location
    if (delta.player.currentNodeId)
      nextPlayer.currentNodeId = delta.player.currentNodeId
    if (typeof delta.player.day === 'number')
      nextPlayer.day = nextPlayer.day + delta.player.day

    nextState.player = nextPlayer
  }

  if (delta.band) {
    const nextBand = { ...nextState.band }
    if (typeof delta.band.harmony === 'number') {
      const nextHarmony = clampBandHarmony(
        nextBand.harmony + delta.band.harmony
      )
      nextBand.harmony = nextHarmony
    }

    const membersDelta = delta.band.membersDelta ?? delta.band.members
    const relationshipChange = delta.band.relationshipChange
    const skillDelta = delta.band.skill

    if (membersDelta || relationshipChange || typeof skillDelta === 'number') {
      const isArrayDelta = Array.isArray(membersDelta)
      const memberCount = nextBand.members.length
      let updatedMembers = null
      let bandChanged = false

      for (let i = 0; i < memberCount; i++) {
        const member = nextBand.members[i]
        let nextMember = member
        let memberHasChanges = false

        // 1. Mood & Stamina
        if (membersDelta) {
          const mDelta = isArrayDelta ? membersDelta[i] || {} : membersDelta
          const moodChange =
            typeof mDelta.moodChange === 'number' ? mDelta.moodChange : 0
          const staminaChange =
            typeof mDelta.staminaChange === 'number' ? mDelta.staminaChange : 0

          if (moodChange !== 0 || staminaChange !== 0) {
            const newMood = clampMemberMood(member.mood + moodChange)
            const newStamina = clampMemberStamina(
              member.stamina + staminaChange,
              member.staminaMax
            )

            if (newMood !== member.mood || newStamina !== member.stamina) {
              nextMember = { ...nextMember, mood: newMood, stamina: newStamina }
              memberHasChanges = true
            }
          }
        }

        // 2. Relationships
        if (relationshipChange) {
          let newRelationships = null
          const hasGrudgeHolder = hasTrait(member, 'grudge_holder')
          const hasPeacemaker = hasTrait(member, 'peacemaker')

          for (let j = 0; j < relationshipChange.length; j++) {
            const change = relationshipChange[j]
            const relSource = newRelationships || nextMember.relationships || {}

            const result = calculateMemberRelationshipChange(
              change,
              member.name,
              hasGrudgeHolder,
              hasPeacemaker,
              relSource
            )

            if (result) {
              const { other, newScore } = result
              const oldExists = Object.hasOwn(relSource, other)

              if (oldExists || newScore !== RELATIONSHIP_DEFAULT_SCORE) {
                if (!newRelationships) {
                  newRelationships = { ...(nextMember.relationships || {}) }
                }
                newRelationships[other] = newScore
              }
            }
          }

          if (newRelationships) {
            let relationshipsActuallyChanged = false
            const newRelKeys = Object.keys(newRelationships)
            for (let k = 0; k < newRelKeys.length; k++) {
              const key = newRelKeys[k]
              if (!key) continue
              if (newRelationships[key] !== member.relationships?.[key]) {
                relationshipsActuallyChanged = true
                break
              }
            }

            if (relationshipsActuallyChanged) {
              if (nextMember === member) nextMember = { ...member }
              nextMember.relationships = newRelationships
              memberHasChanges = true
            }
          }
        }

        // 3. Skill
        if (typeof skillDelta === 'number' && skillDelta !== 0) {
          const currentSkill =
            member.baseStats && typeof member.baseStats.skill === 'number'
              ? member.baseStats.skill
              : 5
          const newSkill = Math.max(1, Math.min(10, currentSkill + skillDelta))

          if (newSkill !== currentSkill) {
            if (nextMember === member) nextMember = { ...member }
            nextMember.baseStats = {
              ...nextMember.baseStats,
              skill: newSkill
            }
            memberHasChanges = true
          }
        }

        if (memberHasChanges) {
          if (!bandChanged) {
            bandChanged = true
            updatedMembers = [...nextBand.members]
          }
          // updatedMembers is initialized above when bandChanged flips to true
          if (updatedMembers) {
            updatedMembers[i] = nextMember
          }
        } else if (bandChanged) {
          // If bandChanged already true, ensure updatedMembers exists then assign
          if (!updatedMembers) updatedMembers = [...nextBand.members]
          updatedMembers[i] = member
        }
      }

      if (bandChanged && updatedMembers) {
        nextBand.members = updatedMembers
      }
    }

    if (delta.band.inventory) {
      nextBand.inventory = { ...nextBand.inventory }
      const bandInventoryKeys = Object.keys(delta.band.inventory)
      for (let i = 0; i < bandInventoryKeys.length; i++) {
        const item = bandInventoryKeys[i]
        if (!item) continue
        if (isForbiddenKey(item)) continue
        const val = delta.band.inventory[item]
        nextBand.inventory[item] = applyInventoryItemDelta(
          nextBand.inventory[item],
          val
        )
      }
    }

    if (delta.band.stashRemove && Array.isArray(delta.band.stashRemove)) {
      nextBand.stash = Object.assign(Object.create(null), nextBand.stash || {})
      for (let i = 0; i < delta.band.stashRemove.length; i++) {
        const itemId = delta.band.stashRemove[i]
        if (!itemId) continue
        if (typeof itemId === 'string' && !isForbiddenKey(itemId)) {
          delete nextBand.stash[itemId]
        }
      }
    }

    if (typeof delta.band.luck === 'number') {
      const boundedLuck = clampNonNegative(nextBand.luck)
      nextBand.luck = boundedLuck + delta.band.luck
    }
    nextState.band = nextBand
  }

  if (delta.social) {
    const nextSocial = { ...nextState.social }
    const socialKeys = Object.keys(delta.social)
    for (let i = 0; i < socialKeys.length; i++) {
      const key = socialKeys[i]
      if (!key) continue
      if (isForbiddenKey(key)) continue
      const value = delta.social[key]

      if (key === 'controversyLevel') {
        if (typeof value === 'number') {
          const newValue = clampControversyLevel(
            (typeof nextSocial[key] === 'number' ? nextSocial[key] : 0) + value
          )
          nextSocial[key] = newValue
        }
      } else if (key === 'influencers') {
        if (
          typeof value === 'object' &&
          value !== null &&
          !Array.isArray(value)
        ) {
          const safeInfluencersUpdate = copyFilteredProperties(value)
          nextSocial[key] = {
            ...(nextSocial[key] || {}),
            ...safeInfluencersUpdate
          }
        }
      } else if (key === 'egoFocus') {
        if (value === null || typeof value === 'string') {
          nextSocial[key] = value
        }
      } else if (key === 'trend') {
        if (typeof value === 'string') {
          nextSocial[key] = value
        }
      } else if (key === 'lastGigDay' || key === 'lastGigDifficulty') {
        if (
          value === null ||
          (typeof value === 'number' && Number.isFinite(value))
        ) {
          nextSocial[key] = value
        }
      } else if (typeof value === 'number') {
        const currentValue =
          typeof nextSocial[key] === 'number' ? nextSocial[key] : 0
        nextSocial[key] = Math.max(0, currentValue + value)
      }
    }
    nextState.social = nextSocial
  }

  if (delta.flags) {
    if (delta.flags.addStoryFlag) {
      if (!nextState.activeStoryFlags.includes(delta.flags.addStoryFlag)) {
        nextState.activeStoryFlags = [
          ...nextState.activeStoryFlags,
          delta.flags.addStoryFlag
        ]
      }
    }
    if (delta.flags.queueEvent) {
      nextState.pendingEvents = [
        ...nextState.pendingEvents,
        delta.flags.queueEvent
      ]
    }
    if (delta.flags.addCooldown) {
      if (!nextState.eventCooldowns.includes(delta.flags.addCooldown)) {
        nextState.eventCooldowns = [
          ...nextState.eventCooldowns,
          delta.flags.addCooldown
        ]
      }
    }
  }

  return nextState
}

/**
 * Checks if a collection (Set or Array) contains an item.
 * Used primarily for optimizedState which passes Sets instead of Arrays for performance.
 *
 * @param {Set|Array} collection - The collection to check.
 * @param {any} item - The item to look for.
 * @returns {boolean} True if the collection contains the item.
 */
export const hasStateItem = (
  collection: Set<any> | any[] | null | undefined,
  item: any
): boolean => {
  return collection instanceof Set
    ? collection.has(item)
    : (collection || []).includes(item)
}

/**
 * Checks if the player has an active, non-expired sponsorship brand deal.
 * activeDeals stores deal objects with { id, type, remainingGigs, ... }.
 * Deals with remainingGigs <= 0 are considered expired even if not yet filtered.
 * @param {object} socialState
 * @returns {boolean}
 */
export const hasActiveSponsorship = (socialState: any): boolean => {
  return (socialState?.activeDeals || []).some(
    (d: any) => d.type === 'SPONSORSHIP' && (d.remainingGigs ?? 1) > 0
  )
}

/**
 * Normalizes an unknown setlist payload to an array of objects with an 'id' property.
 * @param {unknown} setlist - The setlist payload to normalize.
 * @returns {Array<{ id: string }>} Normalized setlist.
 */
export const normalizeSetlistForSave = (
  setlist: unknown
): Array<{ id: string }> => {
  if (!Array.isArray(setlist)) return []

  const result: { id: string }[] = []
  for (const song of setlist) {
    if (typeof song === 'string') {
      result.push({ id: song })
    } else if (
      song &&
      typeof song === 'object' &&
      typeof (song as { id?: unknown }).id === 'string'
    ) {
      result.push({ id: (song as { id: string }).id })
    }
  }
  return result
}

import { getSafeRandom } from './crypto'

/**
 * Updates the state of active projectiles.
 * @param {Array} projectiles - Current list of projectiles.
 * @param {number} deltaMS - Time elapsed in milliseconds.
 * @param {number} screenHeight - Height of the screen (to determine despawn).
 * @returns {Array} Updated list of projectiles.
 */
// Adaptive difficulty AI tuning based on stats
export const createHecklerSession = (): { pool: any[]; nextId: number } => ({
  pool: [],
  nextId: 0
})

const SPAWN_CHANCE_CONFIG = {
  BASE: 0.0005,
  COMBO_HIGH_THRESHOLD: 50,
  COMBO_HIGH_BONUS: 0.002,
  COMBO_MEDIUM_THRESHOLD: 20,
  COMBO_MEDIUM_BONUS: 0.001,
  HEALTH_LOW_THRESHOLD: 30,
  HEALTH_LOW_BONUS: 0.003,
  HEALTH_MEDIUM_THRESHOLD: 60,
  HEALTH_MEDIUM_BONUS: 0.001
}

export const processProjectiles = (
  session: any,
  projectiles: any[],
  deltaMS: number,
  screenHeight = 1080,
  onHit?: (p: any) => void
): any[] => {
  const despawnY = screenHeight + 100
  const hitY = screenHeight - 150
  let writeIdx = 0

  for (let i = 0; i < projectiles.length; i++) {
    const p = projectiles[i]

    if (p.x === undefined) p.x = 0
    if (p.rotation === undefined) p.rotation = 0

    // 1. Apply Physics
    if (p.vy !== undefined) p.y += p.vy * deltaMS
    if (p.vx !== undefined) p.x += p.vx * deltaMS
    if (p.vr !== undefined) p.rotation += p.vr * deltaMS

    // 2. Check Collision & Despawn
    let hit = false
    // We check if the projectile crossed the hitY threshold in this tick.
    // If it also crossed despawnY due to a lag spike, it skips the hit penalty.
    if (onHit && p.y > hitY && p.y < despawnY) {
      onHit(p)
      hit = true
    }

    // 3. Keep if not hit AND above despawn limit
    if (!hit && p.y < despawnY) {
      if (i !== writeIdx) projectiles[writeIdx] = p
      writeIdx++
    } else {
      if (session.pool.length < MAX_PROJECTILE_POOL_SIZE) {
        // Remove any dynamically added properties to prevent leaks without allocating a new object
        for (const key in p) {
          if (
            key !== 'id' &&
            key !== 'x' &&
            key !== 'y' &&
            key !== 'vx' &&
            key !== 'vy' &&
            key !== 'rotation' &&
            key !== 'vr' &&
            key !== 'type'
          ) {
            delete p[key]
          }
        }
        session.pool.push(p)
      }
    }
  }

  if (writeIdx < projectiles.length) projectiles.length = writeIdx
  return projectiles
}

/**
 * Determines if a new projectile should be spawned and generates it.
 * @param {object} stats - Game stats (health, combo).
 * @param {Function} [random=getSafeRandom] - Random number generator.
 * @param {number} [screenWidth=1920] - Width of screen for random X position.
 * @returns {object|null} New projectile object or null.
 */
const MAX_PROJECTILE_POOL_SIZE = 64

export const trySpawnProjectile = (
  session: any,
  stats: { combo?: number; health?: number },
  random: () => number = getSafeRandom,
  screenWidth = 1920
): any | null => {
  // Adaptive difficulty AI tuning based on stats
  let spawnChance = SPAWN_CHANCE_CONFIG.BASE
  // Normalize optional stats
  const combo = typeof stats.combo === 'number' ? stats.combo : 0
  const health = typeof stats.health === 'number' ? stats.health : 100

  // Jealousy from high combo
  if (combo > SPAWN_CHANCE_CONFIG.COMBO_HIGH_THRESHOLD) {
    spawnChance += SPAWN_CHANCE_CONFIG.COMBO_HIGH_BONUS
  } else if (combo > SPAWN_CHANCE_CONFIG.COMBO_MEDIUM_THRESHOLD) {
    spawnChance += SPAWN_CHANCE_CONFIG.COMBO_MEDIUM_BONUS
  }

  // Desperation when health is low (piling on)
  if (health < SPAWN_CHANCE_CONFIG.HEALTH_LOW_THRESHOLD) {
    spawnChance += SPAWN_CHANCE_CONFIG.HEALTH_LOW_BONUS
  } else if (health < SPAWN_CHANCE_CONFIG.HEALTH_MEDIUM_THRESHOLD) {
    spawnChance += SPAWN_CHANCE_CONFIG.HEALTH_MEDIUM_BONUS
  }

  if (random() < spawnChance) {
    let p
    if (session.pool.length > 0) {
      p = session.pool.pop()
      p.id = session.nextId++
      p.x = random() * screenWidth
      p.y = -100
      p.vx = (random() - 0.5) * 0.5
      p.vy = 0.3 + random() * 0.4
      p.rotation = 0
      p.vr = (random() - 0.5) * 0.2
      p.type = random() > 0.5 ? 'bottle' : 'tomato'
    } else {
      p = {
        id: session.nextId++,
        x: random() * screenWidth,
        y: -100, // Start above screen
        vx: (random() - 0.5) * 0.5, // Drift left/right
        vy: 0.3 + random() * 0.4, // Fall speed
        rotation: 0,
        vr: (random() - 0.5) * 0.2, // Rotation speed
        type: random() > 0.5 ? 'bottle' : 'tomato'
      }
    }
    return p
  }
  return null
}

/// <reference types="vite/client" />
import { getSafeUUID } from './crypto'

/**
 * Log levels for the application.
 */
export const LOG_LEVELS = {
  DEBUG: 0,
  INFO: 1,
  WARN: 2,
  ERROR: 3,
  NONE: 4
}

/**
 * A configurable logger system for debugging game flow.
 */
export class Logger {
  logs: any[]
  maxLogs: number
  minLevel: number
  listeners: Array<(event: any) => void>
  constructor() {
    this.logs = []
    this.maxLogs = 1000
    this.minLevel = LOG_LEVELS.DEBUG // Default to DEBUG for now, can be changed via settings
    this.listeners = []

    // Load preference if available
    try {
      const savedLevel = localStorage.getItem('neurotoxic_log_level')
      if (savedLevel) this.minLevel = parseInt(savedLevel, 10)
    } catch (_e) {
      // Ignore storage errors
    }
  }

  /**
   * Set the minimum log level filter.
   * @param {number} level
   */
  setLevel(level: number): void {
    this.minLevel = level
    try {
      localStorage.setItem('neurotoxic_log_level', String(level))
    } catch (_e) {
      // Ignore storage errors
    }
  }

  /**
   * Subscribe to log updates (for UI).
   * @param {Function} callback - Callback receiving {type, entry}.
   * @returns {Function} Unsubscribe function
   */
  subscribe(
    callback: (event: { type: string; entry: any }) => void
  ): () => void {
    this.listeners.push(callback)
    return () => {
      this.listeners = this.listeners.filter(l => l !== callback)
    }
  }

  /**
   * Emits log updates to subscribers.
   * @param {object} event - Event object { type, entry }.
   * @private
   */
  _emit(event: any): void {
    this.listeners.forEach(cb => {
      cb(event)
    })
  }

  /**
   * Pushes a new log entry and trims history.
   * @param {object} entry - Log entry.
   * @private
   */
  _push(entry: any): void {
    this.logs.unshift(entry) // Newest first
    if (this.logs.length > this.maxLogs) {
      this.logs.pop()
    }
    this._emit({ type: 'add', entry })
  }

  /**
   * Formats a log message into a structured object.
   * @param {string} level - Log level.
   * @param {string} channel - Source channel.
   * @param {string} message - Message text.
   * @param {any} data - Associated data.
   * @returns {object} Formatted log object.
   * @private
   */
  _format(
    level: string,
    channel: string,
    message: string,
    data: any
  ): {
    id: string
    timestamp: string
    level: string
    channel: string
    message: string
    data: any
  } {
    return {
      id: getSafeUUID(),
      timestamp: new Date().toISOString(),
      level,
      channel,
      message,
      data
    }
  }

  /**
   * Logs a debug message.
   * @param {string} channel - The source channel (e.g. 'Audio', 'GameLoop').
   * @param {string} message - The log message.
   * @param {any} [data] - Optional data to attach.
   */
  debug(channel: string, message: string, data?: any): void {
    if (this.minLevel > LOG_LEVELS.DEBUG) return
    if (!import.meta.env?.PROD) {
      console.debug(`[${channel}] ${message}`, data || '')
    }
    this._push(this._format('DEBUG', channel, message, data))
  }

  /**
   * Logs an informational message.
   * @param {string} channel - The source channel.
   * @param {string} message - The log message.
   * @param {any} [data] - Optional data.
   */
  info(channel: string, message: string, data?: any): void {
    if (this.minLevel > LOG_LEVELS.INFO) return
    if (!import.meta.env?.PROD) {
      console.info(`[${channel}] ${message}`, data || '')
    }
    this._push(this._format('INFO', channel, message, data))
  }

  /**
   * Logs a warning message.
   * @param {string} channel - The source channel.
   * @param {string} message - The log message.
   * @param {any} [data] - Optional data.
   */
  warn(channel: string, message: string, data?: any): void {
    if (this.minLevel > LOG_LEVELS.WARN) return
    console.warn(`[${channel}] ${message}`, data || '')
    this._push(this._format('WARN', channel, message, data))
  }

  /**
   * Logs an error message.
   * @param {string} channel - The source channel.
   * @param {string} message - The log message.
   * @param {any} [data] - Optional data (usually the error object).
   */
  error(channel: string, message: string, data?: any): void {
    if (this.minLevel > LOG_LEVELS.ERROR) return
    console.error(`[${channel}] ${message}`, data || '')
    this._push(this._format('ERROR', channel, message, data))
  }

  /**
   * Clears all stored logs.
   */
  clear(): void {
    this.logs = []
    this._emit({ type: 'clear' })
  }

  /**
   * Dumps logs as a JSON string.
   * @returns {string} JSON representation of logs.
   */
  dump(): string {
    return JSON.stringify(this.logs, null, 2)
  }
}

export const logger = new Logger()

import { calculateRefuelCost, calculateTravelExpenses } from './economyEngine'

/**
 * Checks if a target node is connected to the source node.
 * @param {object} gameMap - The game map object.
 * @param {string} fromNodeId - The source node ID.
 * @param {string} targetNodeId - The target node ID.
 * @returns {boolean} True if connected.
 */
export const isConnected = (
  gameMap: any,
  fromNodeId: string,
  targetNodeId: string
): boolean => {
  if (!gameMap) return false
  if (!gameMap.connections) {
    throw new TypeError('gameMap.connections is missing')
  }
  for (let i = 0; i < gameMap.connections.length; i++) {
    const c = gameMap.connections[i]
    if (c.from === fromNodeId && c.to === targetNodeId) {
      return true
    }
  }
  return false
}

/**
 * Determines the visibility state of a node based on its layer.
 * @param {number} nodeLayer - Target node layer.
 * @param {number} currentLayer - Current player layer.
 * @returns {string} 'visible', 'dimmed', or 'hidden'.
 */
export const getNodeVisibility = (
  nodeLayer: number,
  currentLayer: number
): 'visible' | 'dimmed' | 'hidden' => {
  if (nodeLayer <= currentLayer + 1) return 'visible'
  if (nodeLayer === currentLayer + 2) return 'dimmed'
  return 'hidden'
}

/**
 * Normalizes a venue object or string into a raw ID string, stripping legacy namespacing.
 * @param {object|string} venue - The venue object or string to normalize.
 * @returns {string|null} The normalized string ID, or null.
 */
export const normalizeVenueId = (venue: any): string | null => {
  if (!venue) return null
  let id = typeof venue === 'object' ? venue.id || venue.name : venue

  if (typeof id === 'string') {
    const isVenues = id.startsWith('venues:')
    const hasName = id.endsWith('.name')
    if (isVenues && hasName) {
      id = id.slice(7, -5)
    } else if (isVenues) {
      id = id.slice(7)
    } else if (hasName) {
      if (!id.includes(':')) {
        id = id.slice(0, -5)
      }
    }
  }

  return typeof id === 'string' ? id : null
}

/**
 * Checks if the player is softlocked (stranded) due to lack of fuel and money.
 * @param {object} gameMap - The game map object.
 * @param {object} player - The player state object.
 * @param {object} [band=null] - The band state object.
 * @returns {boolean} True if stranded.
 */
export const checkSoftlock = (
  gameMap: any,
  player: any,
  band: any = null
): boolean => {
  if (!gameMap || !player.currentNodeId) return false

  const currentFuel = player.van?.fuel ?? 0
  const currentNode = gameMap.nodes[player.currentNodeId]

  if (!gameMap.connections) {
    throw new TypeError('gameMap.connections is missing')
  }

  let canReachAny = false
  for (let i = 0; i < gameMap.connections.length; i++) {
    const c = gameMap.connections[i]
    if (c.from === player.currentNodeId) {
      const n = gameMap.nodes[c.to]
      if (n) {
        const { fuelLiters } = calculateTravelExpenses(
          n,
          currentNode,
          {
            van: player.van
          },
          band
        )
        if (currentFuel >= fuelLiters) {
          canReachAny = true
          break
        }
      }
    }
  }

  // If cannot reach any neighbor, check if can afford refuel
  // EXCEPTION: If current node is a GIG, player can earn money, so not stranded.
  if (!canReachAny && currentNode?.type !== 'GIG') {
    const refuelCost = calculateRefuelCost(currentFuel)
    const playerMoney = Math.max(0, player.money ?? 0)
    return playerMoney < refuelCost
  }
  return false
}

import { clampPlayerMoney, clampBandHarmony } from './gameStateUtils'

export const checkHasBroadcastedToday = (
  social: any,
  playerDay: number
): boolean => {
  if (!social || typeof playerDay !== 'number') return false
  return social.lastPirateBroadcastDay === playerDay
}

export const validatePirateBroadcast = (
  social: any,
  player: any,
  band: any,
  config: any
): boolean => {
  if (!social || !player || !band || !config) return false

  const hasBroadcastedToday = checkHasBroadcastedToday(social, player.day)

  const currentMoney = clampPlayerMoney(player.money)
  const currentHarmony = clampBandHarmony(band.harmony)

  return (
    !hasBroadcastedToday &&
    config.COST !== undefined &&
    config.HARMONY_COST !== undefined &&
    currentMoney >= config.COST &&
    currentHarmony >= config.HARMONY_COST
  )
}

